  // ── PARTY TRUST / BLACKLIST SYSTEM ──────────────────────────
  static Future<void> savePartyTrust({
    required String uid,
    required String partyName,
    required int trustPoints,
    required bool isBlacklisted,
    String blacklistReason = '',
    List<Map<String, dynamic>> violations = const [],
