    if (vehicleType.toLowerCase().contains(key.toLowerCase().split(' ')[0])) {
      return kMaterialsByVehicleType[key]!;
    }
  }
  return kMaterialsByVehicleType.values.expand((e) => e).toList();
}

// ================================================================
// CROSS-USER SHARING SERVICE
// ================================================================
class CrossUserSharingService {
  static final FirebaseFirestore _db = FirebaseFirestore.instance;

  /// Called when a fleet owner or driver creates/updates an LR.
  /// Pushes the load event to the consignor and fleet owner feeds.
  static Future<void> pushLoadEvent({
    required String ledgerId,
    required String vehicleNo,
    required String route,
    required String driverName,
    required String consignorPhone,
    required String
        status, // 'dispatched', 'in_transit', 'delivered', 'lr_posted'
    String? lrImageUrl,
    double freightAmount = 0,
    String materialName = '',
  }) async {
    if (!FirebaseService.isReady) return;
    try {
      final event = {
        'ledgerId': ledgerId,
        'vehicleNo': vehicleNo,
        'route': route,
        'driverName': driverName,
        'consignorPhone': consignorPhone,
        'status': status,
        'lrImageUrl': lrImageUrl ?? '',
        'freightAmount': freightAmount,
        'materialName': materialName,
        'timestamp': FieldValue.serverTimestamp(),
        'postedBy': FirebaseService.currentUser?.uid ?? 'local',
        'isRead': false,
      };
      await _db.collection('loadEvents').add(event);
      await _db
          .collection('vehicleStatus')
          .doc(vehicleNo.replaceAll(RegExp(r'[^A-Za-z0-9]'), ''))
          .set({
        'vehicleNo': vehicleNo,
        'status': status,
        'isLoaded': status == 'dispatched' || status == 'in_transit',
        'route': route,
        'driverName': driverName,
        'lastUpdated': FieldValue.serverTimestamp(),
        'ledgerId': ledgerId,
      }, SetOptions(merge: true));
    } catch (e) {
      debugPrint('CrossUserSharing error: $e');
    }
  }

  static Stream<QuerySnapshot> loadEventsStream(String consignorPhone) {
    if (!FirebaseService.isReady) return const Stream.empty();
    return _db
        .collection('loadEvents')
        .where('consignorPhone', isEqualTo: consignorPhone)
        .orderBy('timestamp', descending: true)
        .limit(30)
        .snapshots();
  }

  static Stream<DocumentSnapshot?> vehicleStatusStream(String vehicleNo) {
    if (!FirebaseService.isReady) return const Stream.empty();
    return _db
        .collection('vehicleStatus')
        .doc(vehicleNo.replaceAll(RegExp(r'[^A-Za-z0-9]'), ''))
        .snapshots()
        .map((e) => e.exists ? e : null);
  }
}

// ================================================================
// AI ENGINE - ALL 5 MODULES
// ================================================================

// ── AI Data Models ──────────────────────────────────────────────
enum AiInsightType {
  anomaly,
  overdue,
  duplicate,
  lowMargin,
  reconciled,
  maintenance,
  route,
  ocr
}

enum AiSeverity { info, warning, critical }

class AiInsight {
  final String id, title, body, ledgerId, vehicleNo;
  final AiInsightType type;
  final AiSeverity severity;
  final double? amount;
  final String actionLabel;
  final VoidCallback? onAction;
  bool isDismissed;
  AiInsight({
    required this.id,
    required this.title,
    required this.body,
    this.ledgerId = '',
    this.vehicleNo = '',
    required this.type,
    this.severity = AiSeverity.info,
    this.amount,
    this.actionLabel = '',
    this.onAction,
    this.isDismissed = false,
  });

  Color get severityColor => severity == AiSeverity.critical
      ? const Color(0xFFEF4444)
      : severity == AiSeverity.warning
          ? const Color(0xFFF59E0B)
          : const Color(0xFF0EA5E9);

  IconData get icon {
    switch (type) {
      case AiInsightType.anomaly:
        return Icons.warning_amber_rounded;
      case AiInsightType.overdue:
        return Icons.payment_rounded;
      case AiInsightType.duplicate:
        return Icons.copy_rounded;
      case AiInsightType.lowMargin:
        return Icons.trending_down_rounded;
      case AiInsightType.reconciled:
        return Icons.check_circle_rounded;
      case AiInsightType.maintenance:
        return Icons.build_circle_rounded;
      case AiInsightType.route:
        return Icons.route_rounded;
      case AiInsightType.ocr:
        return Icons.document_scanner_rounded;
    }
  }
}

