  Widget _calcRow(String label, String val, Color color,
          {String? sub, bool isBold = false}) =>
      Padding(
          padding: const EdgeInsets.symmetric(vertical: 2),
          child: Row(children: [
            Expanded(
                child: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
