  Widget _dialogStat(String label, String value, Color color) => Container(
        padding: const EdgeInsets.all(10),
        decoration: BoxDecoration(
          color: color.withOpacity(0.08),
          borderRadius: BorderRadius.circular(10),
          border: Border.all(color: color.withOpacity(0.25)),
        ),
        child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
          Text(label,
              style: TextStyle(
                  color: kSubtext, fontSize: 9, fontWeight: FontWeight.w700)),
          const SizedBox(height: 3),
          Text(value,
              style: TextStyle(
                  color: color, fontWeight: FontWeight.w900, fontSize: 14)),
        ]),
      );

  void _showAiDetail(String title, String body, IconData icon, Color color) {
    showDialog(
        context: context,
        builder: (_) => AlertDialog(
              shape: RoundedRectangleBorder(
                  borderRadius: BorderRadius.circular(18)),
              title: Row(children: [
                Icon(icon, color: color, size: 22),
                const SizedBox(width: 10),
                Expanded(
                    child: Text(title,
                        style: const TextStyle(
                            fontWeight: FontWeight.w900, fontSize: 17))),
              ]),
              content: SingleChildScrollView(
                  child: Text(body,
                      style: const TextStyle(
                          height: 1.45,
                          fontSize: 13,
                          color: Color(0xFF334155)))),
              actions: [
                TextButton(
                    onPressed: () => Navigator.pop(context),
                    child: const Text('Close'))
              ],
            ));
  }

  Widget _insightCard(AiInsight insight,
      {VoidCallback? onDismiss, VoidCallback? onTapCard}) {
    final tap = onTapCard ??
        insight.onAction ??
        () => _showAiDetail(
              insight.title,
              '${insight.body}\n\nSeverity: ${insight.severity.name.toUpperCase()}${insight.amount != null ? "\nAmount: Rs.${insight.amount!.abs().toStringAsFixed(0)}" : ""}',
              insight.icon,
              insight.severityColor,
            );
    return Material(
        color: Colors.transparent,
        child: InkWell(
            borderRadius: BorderRadius.circular(14),
            onTap: tap,
            splashColor: insight.severityColor.withOpacity(0.15),
            highlightColor: insight.severityColor.withOpacity(0.08),
            child: Container(
                margin: const EdgeInsets.only(bottom: 10),
                decoration: BoxDecoration(
                    color: kCard,
                    borderRadius: BorderRadius.circular(14),
                    border: Border.all(
                        color: insight.severityColor.withOpacity(0.25)),
                    boxShadow: [
                      BoxShadow(
                          color: insight.severityColor.withOpacity(0.07),
                          blurRadius: 8)
                    ]),
                child: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      Container(
                          padding: const EdgeInsets.symmetric(
                              horizontal: 14, vertical: 10),
                          decoration: BoxDecoration(
                              color: insight.severityColor.withOpacity(0.07),
                              borderRadius: const BorderRadius.vertical(
                                  top: Radius.circular(13))),
                          child: Row(children: [
                            Container(
                                padding: const EdgeInsets.all(6),
                                decoration: BoxDecoration(
                                    color:
                                        insight.severityColor.withOpacity(0.12),
                                    borderRadius: BorderRadius.circular(8)),
                                child: Icon(insight.icon,
                                    color: insight.severityColor, size: 14)),
                            const SizedBox(width: 8),
                            Expanded(
                                child: Text(insight.title,
                                    style: TextStyle(
                                        color: insight.severityColor,
                                        fontWeight: FontWeight.w800,
                                        fontSize: 13))),
                            if (onDismiss != null)
                              GestureDetector(
                                  onTap: onDismiss,
                                  child: const Icon(Icons.close_rounded,
                                      color: kSubtext, size: 16)),
                          ])),
                      Padding(
                          padding: const EdgeInsets.all(14),
                          child: Column(
                              crossAxisAlignment: CrossAxisAlignment.start,
                              children: [
                                Text(insight.body,
                                    style: TextStyle(
                                        color: kSubtext,
                                        fontSize: 12,
                                        height: 1.5)),
                                if (insight.amount != null) ...[
                                  const SizedBox(height: 10),
                                  Row(children: [
                                    Container(
                                        padding: const EdgeInsets.symmetric(
                                            horizontal: 10, vertical: 5),
                                        decoration: BoxDecoration(
                                            color: insight.severityColor
                                                .withOpacity(0.1),
                                            borderRadius:
                                                BorderRadius.circular(8)),
