                                                fontSize: 13))),
                                    const Spacer(),
                                    if (insight.actionLabel.isNotEmpty)
                                      ElevatedButton(
                                          style: ElevatedButton.styleFrom(
                                              backgroundColor:
                                                  insight.severityColor,
                                              foregroundColor: Colors.white,
                                              shape: RoundedRectangleBorder(
                                                  borderRadius:
                                                      BorderRadius.circular(8)),
                                              padding:
                                                  const EdgeInsets.symmetric(
                                                      horizontal: 14,
                                                      vertical: 8),
                                              elevation: 0),
                                          onPressed: onTapCard ??
                                              insight.onAction ??
                                              () {},
                                          child: Text(insight.actionLabel,
                                              style: const TextStyle(
                                                  fontSize: 12,
                                                  fontWeight:
                                                      FontWeight.w800))),
                                  ]),
                                ],
                              ])),
                    ]))));
  }

  Widget _reconcileCard(AiReconciliationSuggestion r) {
    final pct = (r.confidence * 100).round();
    final color = pct >= 70
        ? kSuccess
        : pct >= 45
            ? kWarning
            : kSubtext;
    return Container(
        margin: const EdgeInsets.only(bottom: 12),
        decoration: BoxDecoration(
            color: kCard,
            borderRadius: BorderRadius.circular(14),
            border: Border.all(color: color.withOpacity(0.3)),
            boxShadow: [
              BoxShadow(color: color.withOpacity(0.06), blurRadius: 8)
            ]),
        child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
          // Header
          Container(
              padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 10),
              decoration: BoxDecoration(
                  color: color.withOpacity(0.06),
                  borderRadius:
                      const BorderRadius.vertical(top: Radius.circular(13))),
              child: Row(children: [
                Container(
                    padding:
                        const EdgeInsets.symmetric(horizontal: 8, vertical: 3),
                    decoration: BoxDecoration(
                        color: color.withOpacity(0.15),
                        borderRadius: BorderRadius.circular(8)),
                    child: Text('$pct% match',
                        style: TextStyle(
                            color: color,
                            fontSize: 11,
                            fontWeight: FontWeight.w900))),
                const SizedBox(width: 8),
                Text(r.reason, style: TextStyle(color: kSubtext, fontSize: 10)),
                const Spacer(),
                Text(r.bankEntry.date,
                    style: TextStyle(color: kSubtext, fontSize: 11)),
              ])),
          // Body
          Padding(
              padding: const EdgeInsets.all(14),
              child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Row(children: [
                      Expanded(
                          child: Column(
                              crossAxisAlignment: CrossAxisAlignment.start,
                              children: [
                            const Text('BANK CREDIT',
                                style: TextStyle(
                                    color: kSubtext,
                                    fontSize: 9,
                                    fontWeight: FontWeight.w700,
                                    letterSpacing: 0.5)),
                            Text('₹${r.bankEntry.credit.toStringAsFixed(0)}',
                                style: TextStyle(
                                    color: kText,
                                    fontWeight: FontWeight.w900,
                                    fontSize: 18)),
                            Text(r.bankEntry.narration,
                                style: TextStyle(color: kSubtext, fontSize: 11),
                                maxLines: 1,
                                overflow: TextOverflow.ellipsis),
                          ])),
                      Container(
                          padding: const EdgeInsets.all(6),
                          decoration: BoxDecoration(
                              color: kPrimary.withOpacity(0.1),
                              shape: BoxShape.circle),
                          child: const Icon(Icons.arrow_forward_rounded,
                              color: kPrimary, size: 16)),
                      Expanded(
                          child: Column(
                              crossAxisAlignment: CrossAxisAlignment.end,
                              children: [
                            const Text('LEDGER PENDING',
                                style: TextStyle(
                                    color: kSubtext,
                                    fontSize: 9,
                                    fontWeight: FontWeight.w700,
                                    letterSpacing: 0.5)),
                            Text('₹${r.ledger.partyPending.toStringAsFixed(0)}',
                                style: TextStyle(
                                    color: kPrimary,
                                    fontWeight: FontWeight.w900,
                                    fontSize: 18)),
                            Text(r.ledger.partyName,
                                style: TextStyle(color: kSubtext, fontSize: 11),
                                maxLines: 1,
                                overflow: TextOverflow.ellipsis),
                          ])),
                    ]),
                    const SizedBox(height: 12),
                    SizedBox(
                        width: double.infinity,
                        child: ElevatedButton.icon(
                            style: ElevatedButton.styleFrom(
                                backgroundColor: color,
                                foregroundColor: Colors.white,
                                padding:
                                    const EdgeInsets.symmetric(vertical: 12),
                                shape: RoundedRectangleBorder(
                                    borderRadius: BorderRadius.circular(10)),
                                elevation: 2,
                                shadowColor: color.withOpacity(0.3)),
                            onPressed: () {
                              widget.onApplyReconciliation
                                  ?.call(r.ledger.id, r.bankEntry.credit);
                              setState(() {
                                r.bankEntry.isMatched = true;
                                _reconciliations.removeWhere(
                                    (x) => x.bankEntry == r.bankEntry);
                              });
                              _snack(
                                  '✅ ₹${r.bankEntry.credit.toStringAsFixed(0)} applied to ${r.ledger.partyName}');
                            },
                            icon: const Icon(Icons.check_circle_rounded,
                                size: 16),
                            label: const Text('Apply Reconciliation',
                                style: TextStyle(
                                    fontWeight: FontWeight.w900,
                                    fontSize: 14)))),
                  ])),
        ]));
  }

