class SplashScreen extends StatefulWidget {
  const SplashScreen({super.key});
  @override
  State<SplashScreen> createState() => _SplashScreenState();
}

class _SplashScreenState extends State<SplashScreen>
    with SingleTickerProviderStateMixin {
  late AnimationController _c;
  @override
  void initState() {
    super.initState();
    _c = AnimationController(
        vsync: this, duration: const Duration(milliseconds: 900))
      ..forward();
    Timer(const Duration(seconds: 3), () async {
      if (!mounted) return;
      // Primary: check Firebase auth state (handles token expiry correctly)
      final firebaseUser = FirebaseService.currentUser;
      final prefs = await SharedPreferences.getInstance();
      final sessionActive = prefs.getBool('rm_session_active') ?? false;
      // Logged in if Firebase says so OR if session was active and Firebase not initialized
      // Firebase auth token is persistent - if currentUser != null, user is logged in
      // sessionActive is a backup for when Firebase isn't initialized
      final isLoggedIn =
          (firebaseUser != null) || (sessionActive && !FirebaseService.isReady);
      // If session was marked active but Firebase says no user, clear stale session
      if (!isLoggedIn && sessionActive) {
        await prefs.setBool('rm_session_active', false);
      }
      if (!mounted) return;
      Navigator.pushReplacement(
          context,
          MaterialPageRoute(
              builder: (_) =>
                  isLoggedIn ? const MainShell() : const LoginScreen()));
    });
  }

  @override
  void dispose() {
    _c.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final size = MediaQuery.of(context).size;
    return Scaffold(
      backgroundColor: const Color(0xFFF6FAFF),
      body: Stack(children: [
        // Warm morning gradient wash
        Positioned.fill(
            child: Container(
          decoration: const BoxDecoration(
            gradient: LinearGradient(
              colors: [Color(0xFFF6FAFF), Color(0xFFEFF6FF), Color(0xFFE2E8F0)],
              begin: Alignment.topCenter,
              end: Alignment.bottomCenter,
            ),
          ),
        )),
        // Orange glow top-right
        Positioned(
            top: -60,
            right: -40,
            child: Container(
              width: 280,
              height: 280,
              decoration: BoxDecoration(
                shape: BoxShape.circle,
                gradient: RadialGradient(colors: [
                  const Color(0xFF0EA5E9).withOpacity(0.3),
                  Colors.transparent
                ]),
              ),
            )),
        // Soft amber glow bottom-left
        Positioned(
            bottom: -40,
            left: -40,
            child: Container(
              width: 220,
              height: 220,
              decoration: BoxDecoration(
                shape: BoxShape.circle,
                gradient: RadialGradient(colors: [
                  const Color(0xFFF59E0B).withOpacity(0.25),
                  Colors.transparent
                ]),
              ),
            )),
        // Main content
        Center(
            child: FadeTransition(
          opacity: CurvedAnimation(parent: _c, curve: Curves.easeOut),
          child: Column(mainAxisAlignment: MainAxisAlignment.center, children: [
            ScaleTransition(
              scale: CurvedAnimation(parent: _c, curve: Curves.elasticOut),
              child: _buildLogo(),
            ),
            const SizedBox(height: 32),
