          const SizedBox(height: 24),
          SizedBox(
            width: double.infinity,
            height: 54,
            child: ElevatedButton(
              style: ElevatedButton.styleFrom(
                backgroundColor: const Color(0xFF0EA5E9),
                foregroundColor: const Color(0xFFFFFFFF),
                shape: RoundedRectangleBorder(
                    borderRadius: BorderRadius.circular(14)),
                elevation: 0,
              ),
              onPressed: _saving ? null : _saveAndContinue,
              child: _saving
                  ? const CircularProgressIndicator(
                      color: Color(0xFF0F172A), strokeWidth: 2)
                  : Text(_step < 3 ? "Continue" : "Complete Setup ->",
                      style: const TextStyle(
                          fontSize: 16,
                          fontWeight: FontWeight.w800,
                          color: Color(0xFF0F172A))),
            ),
          ),
        ]),
      )),
    );
  }
}

class LoginScreen extends StatefulWidget {
  const LoginScreen({super.key});
  @override
  State<LoginScreen> createState() => _LoginScreenState();
}

class _LoginScreenState extends State<LoginScreen> {
  bool _sent = false;
  bool _loading = false;
  String? _verificationId;
  String? _errorMsg;
  String _statusMsg = '';
  // Phone field: user types only 10 digits; +91 shown as prefix
  final _phone = TextEditingController();
  final _otp = TextEditingController();

  @override
  void initState() {
    super.initState();
    // Listen and strip any +91 the user manually types
    _phone.addListener(() {
      final t = _phone.text;
      // Strip country code if user pastes or autofills full number
      String cleaned = t
          .replaceAll(RegExp(r'^\+?91'), '')
          .replaceAll(RegExp(r'[\s\-()]'), '');
      if (cleaned != t) {
        _phone.value = TextEditingValue(
          text: cleaned,
          selection: TextSelection.collapsed(offset: cleaned.length),
        );
      }
    });
  }

  Future<void> _sendOTP() async {
    final raw =
        _phone.text.trim().replaceAll(RegExp(r'\s+'), '').replaceAll('+91', '');
    if (raw.length != 10 || !RegExp(r'^[6-9]\d{9}$').hasMatch(raw)) {
      setState(() => _errorMsg = 'Enter a valid 10-digit Indian mobile number');
      return;
    }
    final phone = '+91$raw';
    setState(() {
      _loading = true;
      _errorMsg = null;
      _statusMsg = 'Sending OTP to +91${raw}...';
    });
    await FirebaseService.sendOTP(
      phone: phone,
      onCodeSent: (vid) {
        if (mounted) {
          if (vid == 'AUTO_VERIFIED') {
            // Firebase auto-verified (silent SMS retrieval) — navigate directly
            _handleSuccessfulLogin();
            return;
          }
          setState(() {
            _verificationId = vid;
            _sent = true;
            _loading = false;
            _statusMsg = '';
          });
        }
      },
      onError: (e) {
        if (mounted) {
          setState(() {
            _loading = false;
            _statusMsg = '';
            _errorMsg =
                'OTP failed: ${e.toString().replaceAll(RegExp(r'\[.*?\]'), '').trim()}';
          });
        }
      },
    );
  }

  Future<void> _handleSuccessfulLogin() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setBool('rm_session_active', true);
    final uid = FirebaseService.currentUser?.uid;
    if (uid != null) await prefs.setString('rm_uid', uid);
    bool isNew = true;
    if (uid != null) {
      final profileKey = '${uid}_fm_profile';
      if (prefs.getString(profileKey) != null) {
        isNew = false;
      } else {
        try {
          final doc = await FirebaseService.loadProfile();
          isNew = doc == null || (doc['companyName'] as String? ?? '').isEmpty;
        } catch (_) {
          isNew = false;
        }
      }
    }
    if (!mounted) return;
    Navigator.pushReplacement(
        context,
        MaterialPageRoute(
            builder: (_) =>
                isNew ? const RegistrationScreen() : const MainShell()));
  }

  Future<void> _verifyOTP() async {
    if (_verificationId == null) {
      setState(() => _errorMsg = 'Request OTP first');
      return;
    }
    if (_otp.text.trim().length < 6) {
      setState(() => _errorMsg = 'Enter 6-digit OTP');
      return;
    }
    setState(() {
      _loading = true;
      _errorMsg = null;
    });
    try {
      final ok = await FirebaseService.verifyOTP(
          verificationId: _verificationId!, otp: _otp.text.trim());
      if (!mounted) return;
      if (ok) {
        await _handleSuccessfulLogin();
      } else {
        setState(() {
          _loading = false;
          _errorMsg = 'Incorrect OTP. Check the code and try again.\n'
              'If the problem persists:\n'
              '• Make sure Phone Auth is enabled in Firebase Console\n'
              '• Check SHA-1 fingerprint is added for this device';
        });
      }
    } catch (e) {
      if (!mounted) return;
      setState(() {
        _loading = false;
        _errorMsg = 'Verification error. Try again.';
      });
    }
  }

