          Color(0xFFDBEAFE),
          Color(0xFFF6FAFF)
        ], stops: [
          0.0,
          0.3,
          0.7,
          1.0
        ], begin: Alignment.topCenter, end: Alignment.bottomCenter))),
        CustomPaint(painter: _RouteBgPainter(), size: Size.infinite),
