  void sendOTPToDriver(String phone, Function(bool verified) onResult) {
    String verId = '';
    final otpCtrl = TextEditingController();
    bool codeSent = false, loading = true;
    String err = '';
    final fmtPhone = phone.startsWith('+')
        ? phone
        : '+91${phone.replaceAll(RegExp(r'\D'), '')}';

    showDialog(
        context: context,
        barrierDismissible: false,
        builder: (c) => StatefulBuilder(builder: (c2, ss) {
              if (loading && !codeSent && err.isEmpty) {
                FirebaseService.sendOTP(
                    phone: fmtPhone,
                    onCodeSent: (vid) => ss(() {
                          verId = vid;
                          codeSent = true;
                          loading = false;
                        }),
                    onError: (e) => ss(() {
                          err = e;
                          loading = false;
                        }));
              }
              return AlertDialog(
                shape: RoundedRectangleBorder(
                    borderRadius: BorderRadius.circular(18)),
                title: const Row(children: [
                  Icon(Icons.sms, color: Color(0xFF0F172A)),
                  SizedBox(width: 8),
                  Text("OTP Verification",
                      style: TextStyle(fontWeight: FontWeight.w800))
                ]),
                content: loading
                    ? const SizedBox(
                        height: 70,
                        child: Center(
                            child: Column(
                                mainAxisSize: MainAxisSize.min,
                                children: [
                              CircularProgressIndicator(),
                              SizedBox(height: 12),
                              Text("Sending OTP to number...",
                                  style: TextStyle(
                                      color: Colors.grey, fontSize: 13))
                            ])))
                    : err.isNotEmpty
                        ? Column(mainAxisSize: MainAxisSize.min, children: [
                            const Icon(Icons.error_outline,
                                color: Colors.red, size: 44),
                            const SizedBox(height: 10),
                            Text(err,
                                style: const TextStyle(color: Colors.red),
                                textAlign: TextAlign.center),
                            const SizedBox(height: 8),
                            const Text(
                                "Enable Phone Auth in Firebase Console -> Authentication -> Sign-in providers",
                                style:
                                    TextStyle(fontSize: 11, color: Colors.grey),
                                textAlign: TextAlign.center),
                          ])
                        : Column(mainAxisSize: MainAxisSize.min, children: [
                            Container(
                                padding: const EdgeInsets.all(10),
                                decoration: BoxDecoration(
                                    color: Colors.green.withOpacity(0.08),
                                    borderRadius: BorderRadius.circular(10)),
                                child: Row(children: [
                                  const Icon(Icons.check_circle,
                                      color: Colors.green, size: 16),
                                  const SizedBox(width: 8),
                                  Flexible(
                                      child: Text("OTP sent to $fmtPhone",
                                          style: const TextStyle(
                                              color: Colors.green,
                                              fontWeight: FontWeight.w700)))
                                ])),
                            const SizedBox(height: 14),
                            TextField(
                                controller: otpCtrl,
                                keyboardType: TextInputType.number,
                                maxLength: 6,
                                autofocus: true,
                                style: const TextStyle(
                                    fontSize: 22,
                                    fontWeight: FontWeight.w800,
                                    letterSpacing: 8),
                                textAlign: TextAlign.center,
                                decoration: InputDecoration(
                                    labelText: "Enter 6-digit OTP",
                                    border: OutlineInputBorder(
                                        borderRadius:
                                            BorderRadius.circular(12)),
                                    counterText: '')),
                          ]),
                actions: [
                  TextButton(
                      onPressed: () {
                        Navigator.pop(c);
                        onResult(false);
                      },
                      child: const Text("Cancel")),
                  if (codeSent)
                    ElevatedButton.icon(
                        style: ElevatedButton.styleFrom(
                            backgroundColor: const Color(0xFFF6FAFF),
                            shape: RoundedRectangleBorder(
                                borderRadius: BorderRadius.circular(10))),
                        icon: const Icon(Icons.verified,
                            color: Color(0xFF0F172A), size: 16),
                        label: const Text("Verify",
                            style: TextStyle(
                                color: Color(0xFF0F172A),
                                fontWeight: FontWeight.bold)),
                        onPressed: () async {
                          if (otpCtrl.text.length < 6) return;
                          ss(() => loading = true);
                          final ok = await FirebaseService.verifyOTP(
                              verificationId: verId, otp: otpCtrl.text);
                          Navigator.pop(c);
                          onResult(ok);
                          ScaffoldMessenger.of(context).showSnackBar(SnackBar(
                              backgroundColor: ok ? Colors.green : Colors.red,
                              behavior: SnackBarBehavior.floating,
                              content: Text(ok
                                  ? "OK Phone verified!"
                                  : "Incorrect OTP. Try again.")));
                        }),
                ],
              );
            }));
  }

  void _promptAdminPin() {
    final pinCtrl = TextEditingController();
    showDialog(
        context: context,
        builder: (c) => AlertDialog(
              shape: RoundedRectangleBorder(
                  borderRadius: BorderRadius.circular(18)),
              title: const Row(children: [
                Icon(Icons.admin_panel_settings_rounded,
                    color: Color(0xFF0EA5E9)),
                SizedBox(width: 10),
                Text("Admin Dashboard",
                    style: TextStyle(fontWeight: FontWeight.bold))
              ]),
              content: TextField(
                controller: pinCtrl,
                obscureText: true,
                keyboardType: TextInputType.number,
                autofocus: true,
                decoration: InputDecoration(
                  labelText: 'Enter Admin PIN',
                  border: OutlineInputBorder(
                      borderRadius: BorderRadius.circular(10)),
                ),
                onSubmitted: (v) {
                  if (AppConfig.validatePin(v)) {
                    Navigator.pop(c);
                    Navigator.push(
                        context,
                        MaterialPageRoute(
                            builder: (_) => const AdvancedAdminScreen()));
                  }
                },
              ),
              actions: [
                TextButton(
                    onPressed: () => Navigator.pop(c),
                    child: const Text("Cancel")),
                ElevatedButton(
                    style: ElevatedButton.styleFrom(
                        backgroundColor: const Color(0xFF0EA5E9)),
                    onPressed: () {
                      if (AppConfig.validatePin(pinCtrl.text)) {
                        Navigator.pop(c);
                        Navigator.push(
                            context,
                            MaterialPageRoute(
                                builder: (_) => const AdvancedAdminScreen()));
                      } else {
                        ScaffoldMessenger.of(context).showSnackBar(
                            const SnackBar(
                                content: Text('Wrong PIN'),
                                backgroundColor: Colors.red));
                      }
                    },
                    child: const Text("Enter",
                        style: TextStyle(color: Colors.white))),
              ],
            ));
  }

