  Widget _buildDash() {
    final v = _visibleLedgers;
    double rev = v.fold<double>(0, (s, l) => s + l.freightBilled);
    double exp = v.fold(
        0,
        (s, l) =>
            s +
            (l.ownership == VehicleOwnership.self
                ? l.selfExpenses
                : l.marketTruckFreight));
    double profit = v.fold<double>(0, (s, l) => s + l.tripProfit);
    double pending = v.fold<double>(
        0, (s, l) => s + (l.partyPending > 0 ? l.partyPending : 0));
    int dueSoonCount =
        v.where((l) => l.isDueSoon && !l.isPaymentOverdue).length;
    int activeN = v.where((l) => l.partyPending > 0).length;

    return ListView(padding: const EdgeInsets.all(20), children: [
      Row(mainAxisAlignment: MainAxisAlignment.spaceBetween, children: [
        Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
          Text(
              "Good ${DateTime.now().hour < 12 ? 'Morning' : DateTime.now().hour < 17 ? 'Afternoon' : 'Evening'} ",
              style: const TextStyle(
                  fontSize: 13,
                  color: Color(0xFF0F172A),
                  fontWeight: FontWeight.w500)),
          const Text("Operations Hub",
              style: TextStyle(
                  fontSize: 24,
                  fontWeight: FontWeight.w900,
                  color: Color(0xFF0F172A),
                  height: 1.2)),
        ]),
        GestureDetector(
            onTap: _openSub,
            child: Container(
              padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
              decoration: BoxDecoration(
                  gradient: LinearGradient(colors: [
                    subscription.tierColor,
                    subscription.tierColor.withOpacity(0.75)
                  ]),
                  borderRadius: BorderRadius.circular(20),
                  boxShadow: [
                    BoxShadow(
                        color: subscription.tierColor.withOpacity(0.3),
                        blurRadius: 8,
                        offset: const Offset(0, 4))
                  ]),
              child: Row(children: [
                const Icon(Icons.workspace_premium,
                    size: 13, color: Color(0xFF0F172A)),
                const SizedBox(width: 5),
                Text(subscription.tierName,
                    style: const TextStyle(
                        fontSize: 11,
                        fontWeight: FontWeight.w900,
                        color: Color(0xFF0F172A)))
              ]),
            )),
      ]),
      const SizedBox(height: 20),
      if (dueSoonCount > 0)
        Container(
          margin: const EdgeInsets.only(bottom: 12),
          padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 10),
          decoration: BoxDecoration(
              color: Colors.orange.withOpacity(0.08),
              borderRadius: BorderRadius.circular(12),
              border: Border.all(color: Colors.orange[200]!)),
          child: Row(children: [
            Icon(Icons.schedule, color: Colors.orange[700], size: 18),
