                        spacing: 8,
                        children: fleet.take(8).map<Widget>((a) {
                          final asset = a;
                          return GestureDetector(
                              onTap: () => ctrl.text = asset.number,
                              child: Chip(
                                  label: Text(asset.number,
                                      style: const TextStyle(
                                          fontSize: 11,
                                          fontWeight: FontWeight.bold)),
                                  backgroundColor:
                                      Colors.blue.withOpacity(0.18)));
                        }).toList())
                  ]
                ]),
