                                                    final mapsUrl =
                                                        'https://www.google.com/maps/dir/${Uri.encodeComponent(origin)}/${Uri.encodeComponent(dest)}';
                                                    final msg = Uri.encodeComponent(
                                                        '🚛 Route: $origin → $dest\n$mapsUrl');
                                                    final waUrl = Uri.parse(
                                                        'whatsapp://send?text=$msg');
                                                    if (await canLaunchUrl(
                                                        waUrl)) {
                                                      await launchUrl(waUrl);
                                                    } else {
                                                      // WhatsApp not installed, share normally
                                                      SharePlus.instance.share(
                                                          ShareParams(
                                                              text:
                                                                  '🚛 Route: $origin → $dest\n$mapsUrl',
                                                              subject:
                                                                  'Trip Route'));
                                                    }
                                                  },
                                                  icon: const Icon(
                                                      Icons.share_rounded,
                                                      size: 14,
                                                      color: Color(0xFF1A73E8)),
                                                  label: const Text(
                                                      'Share via WhatsApp',
                                                      style: TextStyle(
                                                          fontSize: 12,
                                                          fontWeight:
                                                              FontWeight.w800,
                                                          color:
                                                              Color(0xFF1A73E8)))))),
                                    ]),
                                    const SizedBox(height: 8),
                                    SizedBox(
                                      width: double.infinity,
                                      height: 38,
                                      child: OutlinedButton.icon(
                                          style: OutlinedButton.styleFrom(
                                              side: const BorderSide(
                                                  color: Color(0xFF0EA5E9)),
                                              shape: RoundedRectangleBorder(
                                                  borderRadius:
                                                      BorderRadius.circular(
                                                          10))),
                                          onPressed: () =>
                                              _submitComplaintForConsignor(
                                                  load),
                                          icon: const Icon(
                                              Icons.rate_review_rounded,
                                              size: 14,
                                              color: Color(0xFF0EA5E9)),
                                          label: const Text('Review Consignor',
                                              style: TextStyle(
                                                  fontSize: 12,
                                                  fontWeight: FontWeight.w800,
                                                  color: Color(0xFF0EA5E9)))),
                                    ),
                                  ])),
                        ]));
                  })),
    ]);
  }

