                            borderSide:
                                const BorderSide(color: Color(0xFF0EA5E9))),
                        focusedBorder: OutlineInputBorder(
                            borderRadius: BorderRadius.circular(10),
                            borderSide: const BorderSide(
                                color: Color(0xFF0EA5E9), width: 2))),
                    items: ledgers
                        .map((e) => (e).partyName)
