            ])),
        Expanded(
            child: fl.isEmpty
                ? const Center(
                    child: Column(
                        mainAxisAlignment: MainAxisAlignment.center,
                        children: [
                        Icon(Icons.menu_book, size: 60, color: Colors.grey),
                        SizedBox(height: 12),
                        Text("No trips found",
                            style: TextStyle(
                                color: Colors.grey,
                                fontWeight: FontWeight.bold,
                                fontSize: 16))
                      ]))
                : ListView.builder(
                    padding: const EdgeInsets.all(15),
                    itemCount: fl.length,
                    itemBuilder: (ctx, i) {
                      final l = fl[i];
                      final sc = l.isPaymentOverdue
                          ? Colors.red
                          : l.isDueSoon
                              ? Colors.orange
                              : l.partyPending <= 0
                                  ? Colors.green
                                  : Colors.blueGrey;
                      final st = l.partyPending <= 0
                          ? "Settled"
                          : l.isPaymentOverdue
                              ? "OVERDUE Rs.${l.partyPending.toStringAsFixed(0)}"
                              : l.isDueSoon
