                        // Route
                        const Text("Route Details",
                            style: TextStyle(
                                fontWeight: FontWeight.w800,
                                fontSize: 13,
                                color: Color(0xFF0F172A))),
                        const SizedBox(height: 4),
                        // Origin
                        Container(
                            padding: const EdgeInsets.all(12),
                            decoration: BoxDecoration(
                                color: const Color(0xFFFFFFFF),
                                borderRadius: BorderRadius.circular(12),
                                border: Border.all(
                                    color: Colors.green.withOpacity(0.4))),
                            child: Column(
                                crossAxisAlignment: CrossAxisAlignment.start,
                                children: [
                                  Row(children: [
                                    Container(
                                        width: 10,
                                        height: 10,
                                        decoration: const BoxDecoration(
                                            shape: BoxShape.circle,
                                            color: Colors.green)),
                                    const SizedBox(width: 8),
                                    const Text("LOADING / ORIGIN",
                                        style: TextStyle(
                                            fontSize: 11,
                                            fontWeight: FontWeight.w800,
                                            color: Color(0xFF15803D),
                                            letterSpacing: 1))
                                  ]),
                                  const SizedBox(height: 8),
                                  FactorySearchField(
                                    controller: loFactCtrl,
                                    label: "Factory / Plant Name (Loading)",
                                    iconColor: Colors.green,
                                    onSelected: (name, pid) {
                                      setS(() {
                                        loFactName = name;
                                        loFactPlaceId = pid;
                                        // Auto-extract city from factory address
                                        // e.g. "Vatva GIDC, Ahmedabad, Gujarat" → "Ahmedabad"
                                        if (lOCity.isEmpty) {
                                          final extracted = RoutingEngine
                                              .extractCityFromAddress(name);
                                          if (extracted.isNotEmpty)
                                            lOCity = extracted;
                                        }
                                        if (rCtrl.text.isEmpty) {
                                          rCtrl.text =
                                              "$name -> ${ldFactName.isNotEmpty ? ldFactName : lDCity}";
                                        }
                                      });
                                      // Auto-calc against ANY destination (factory OR city)
                                      final destName = ldFactName.isNotEmpty
                                          ? ldFactName
                                          : lDCity;
                                      final destPid = ldFactPlaceId.isNotEmpty
                                          ? ldFactPlaceId
                                          : lDCityPlaceId;
                                      if (destName.isNotEmpty &&
                                          name.isNotEmpty) {
                                        if (mounted) {
                                          ScaffoldMessenger.of(context)
                                              .showSnackBar(SnackBar(
                                                  backgroundColor:
                                                      const Color(0xFF0EA5E9),
                                                  behavior:
                                                      SnackBarBehavior.floating,
                                                  duration: const Duration(
                                                      seconds: 2),
                                                  content: Row(children: const [
                                                    SizedBox(
                                                        width: 14,
                                                        height: 14,
                                                        child:
                                                            CircularProgressIndicator(
                                                                color: Color(
                                                                    0xFFF6FAFF),
                                                                strokeWidth:
                                                                    2)),
                                                    SizedBox(width: 10),
                                                    Text(
                                                        " Calculating distance via Google Maps...")
                                                  ])));
                                        }
                                        Future.delayed(
                                            const Duration(milliseconds: 400),
                                            () async {
                                          int ax = 6;
                                          try {
                                            if (selVeh != null) {
                                              ax = fleet
                                                  .firstWhere(
                                                      (v) => v.number == selVeh)
                                                  .axleCount;
                                            }
                                          } catch (_) {}
                                          final res =
                                              await RoutingEngine.calculate(
                                                  origin: name,
                                                  destination: destName,
                                                  axles: ax,
                                                  fuelEconomy: double.tryParse(
                                                          feCtrl.text) ??
                                                      3.5,
                                                  originPlaceId: pid,
                                                  destPlaceId: destPid,
                                                  originCity: lOCity,
                                                  destCity: lDCity);
                                          final km = res['km'] as int? ?? 0;
                                          if (km > 0 && mounted) {
                                            setS(() {
                                              distCtrl.text = km.toString();
                                              tolCtrl.text =
                                                  res['toll'].toString();
                                              dslCtrl.text =
                                                  res['diesel'].toString();
                                              calcDone = true;
                                            });
                                            // Show rich result with traffic info
                                            final src =
                                                res['source'] as String? ?? '';
                                            final routeSummary =
                                                res['routeSummary']
                                                        as String? ??
                                                    '';
                                            final durMin =
                                                res['durationMinutes']
                                                        as int? ??
                                                    0;
                                            final durTraffic =
                                                res['durationInTrafficMinutes']
                                                        as int? ??
                                                    0;
                                            final alts =
                                                res['alternatives'] as List? ??
                                                    [];
                                            final trafficDelay =
                                                durTraffic - durMin;
                                            String trafficNote = '';
                                            if (durMin > 0) {
                                              if (trafficDelay >= 15)
                                                trafficNote =
                                                    ' | ⚠️ +${trafficDelay}min traffic delay';
