  // ── Quick button widget for driver cards ────────────────────
  Widget _driverQuickBtn(String label, Color color, VoidCallback onTap) =>
      GestureDetector(
        onTap: onTap,
        child: Container(
          padding: const EdgeInsets.symmetric(vertical: 8),
          decoration: BoxDecoration(
              color: color.withOpacity(0.1),
              borderRadius: BorderRadius.circular(8),
              border: Border.all(color: color.withOpacity(0.35))),
          child: Center(
              child: Text(label,
                  style: TextStyle(
                      color: color,
                      fontSize: 11,
                      fontWeight: FontWeight.w800))),
        ),
      );

  // ── Salary / Advance / Penalty quick action (main shell) ────
  void _quickDriverActionFromMain(Driver d, String action) {
    final ctrl = TextEditingController(
        text: action == "salary" ? d.monthlySalary.toStringAsFixed(0) : "");
    final noteCtrl = TextEditingController();
    final colors = {
      "salary": const Color(0xFF10B981),
      "advance": const Color(0xFFF59E0B),
      "penalty": const Color(0xFFEF4444)
    };
    final labels = {
      "salary": "Pay Salary",
      "advance": "Give Advance",
      "penalty": "Add Penalty"
    };
    showDialog(
        context: context,
        builder: (c) => AlertDialog(
              shape: RoundedRectangleBorder(
                  borderRadius: BorderRadius.circular(18)),
              title: Text("${labels[action]} — ${d.name}",
                  style: TextStyle(
                      color: colors[action]!,
                      fontWeight: FontWeight.w900,
                      fontSize: 16)),
              content: Column(mainAxisSize: MainAxisSize.min, children: [
                TextField(
                    controller: ctrl,
                    keyboardType: TextInputType.number,
                    decoration: InputDecoration(
                        labelText: "Amount (Rs.)",
                        prefixIcon: const Icon(Icons.currency_rupee),
                        border: OutlineInputBorder(
                            borderRadius: BorderRadius.circular(10)))),
                const SizedBox(height: 10),
                TextField(
                    controller: noteCtrl,
                    decoration: InputDecoration(
                        labelText: "Notes",
                        border: OutlineInputBorder(
                            borderRadius: BorderRadius.circular(10)))),
              ]),
              actions: [
                TextButton(
                    onPressed: () => Navigator.pop(c),
                    child: const Text("Cancel")),
                ElevatedButton(
                    style: ElevatedButton.styleFrom(
                        backgroundColor: colors[action]!,
                        foregroundColor: Colors.white,
                        shape: RoundedRectangleBorder(
                            borderRadius: BorderRadius.circular(10))),
                    onPressed: () {
                      double amt = double.tryParse(ctrl.text) ?? 0;
                      if (amt <= 0) return;
                      final txType = action == "salary"
                          ? DriverTxType.salary
                          : action == "advance"
                              ? DriverTxType.advance
                              : DriverTxType.penalty;
                      final sign =
                          (action == "penalty" || action == "advance") ? -1 : 1;
                      setState(() {
                        d.transactions.insert(
                            0,
                            DriverTx(
                                date:
                                    "${DateTime.now().day}/${DateTime.now().month}",
                                type: txType,
                                amount: amt * sign,
                                note: noteCtrl.text.isNotEmpty
                                    ? noteCtrl.text
                                    : action));
                        d.balance += amt * sign;
                      });
                      _save();
                      Navigator.pop(c);
                      ScaffoldMessenger.of(context).showSnackBar(SnackBar(
                          backgroundColor: colors[action]!,
                          behavior: SnackBarBehavior.floating,
                          content: Text(
                              "OK Rs.${amt.toStringAsFixed(0)} recorded for ${d.name}")));
                    },
                    child: const Text("Confirm",
                        style: TextStyle(fontWeight: FontWeight.w800))),
              ],
            ));
  }

  // ── Report issue / Give merit for driver (main shell) ───────
  void _submitComplaintForDriverMain(Driver d, {bool startAsDemerit = true}) {
    final reasonCtrl = TextEditingController();
    int pts = startAsDemerit ? -10 : 10;
    bool isMerit = !startAsDemerit;
    final cats = [
      'Late delivery',
      'Vehicle damage',
      'Rash driving',
      'Dishonesty',
      'Absence without notice',
      'Good service ✓',
      'Excellent trip ✓',
      'Early delivery ✓'
    ];
    showDialog(
        context: context,
        builder: (ctx) => StatefulBuilder(
              builder: (ctx, ss) => AlertDialog(
                shape: RoundedRectangleBorder(
                    borderRadius: BorderRadius.circular(20)),
                title: Text(
                    '${startAsDemerit ? "Report Issue" : "Give Merit"} — ${d.name}',
                    style: const TextStyle(
                        fontWeight: FontWeight.w900, fontSize: 16)),
                content: SingleChildScrollView(
                    child: Column(
                        mainAxisSize: MainAxisSize.min,
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: [
                      const Text('Points apply only after admin approval.',
                          style: TextStyle(color: Colors.grey, fontSize: 12)),
                      const SizedBox(height: 10),
                      Row(children: [
                        Expanded(
                            child: GestureDetector(
                          onTap: () => ss(() {
                            isMerit = false;
                            pts = -10;
                          }),
                          child: Container(
                              padding: const EdgeInsets.symmetric(vertical: 10),
                              decoration: BoxDecoration(
                                  color: !isMerit
                                      ? Colors.red.withOpacity(0.1)
                                      : Colors.transparent,
                                  borderRadius: BorderRadius.circular(10),
                                  border: Border.all(
                                      color: !isMerit
                                          ? Colors.red
                                          : Colors.grey.shade300)),
                              child: const Column(children: [
                                Icon(Icons.thumb_down_rounded,
                                    color: Colors.red),
                                SizedBox(height: 4),
                                Text('Demerit',
                                    style: TextStyle(
                                        fontWeight: FontWeight.w800,
                                        fontSize: 12,
                                        color: Colors.red))
                              ])),
                        )),
                        const SizedBox(width: 10),
                        Expanded(
                            child: GestureDetector(
                          onTap: () => ss(() {
                            isMerit = true;
                            pts = 10;
                          }),
                          child: Container(
                              padding: const EdgeInsets.symmetric(vertical: 10),
                              decoration: BoxDecoration(
                                  color: isMerit
                                      ? Colors.green.withOpacity(0.1)
                                      : Colors.transparent,
                                  borderRadius: BorderRadius.circular(10),
                                  border: Border.all(
                                      color: isMerit
                                          ? Colors.green
                                          : Colors.grey.shade300)),
                              child: const Column(children: [
                                Icon(Icons.thumb_up_rounded,
                                    color: Colors.green),
                                SizedBox(height: 4),
                                Text('Merit',
                                    style: TextStyle(
                                        fontWeight: FontWeight.w800,
                                        fontSize: 12,
                                        color: Colors.green))
                              ])),
                        )),
                      ]),
                      const SizedBox(height: 10),
                      Wrap(
                          spacing: 6,
                          runSpacing: 6,
                          children: cats
                              .map((cat) => GestureDetector(
                                    onTap: () {
                                      reasonCtrl.text = cat;
                                      ss(() {});
                                    },
                                    child: Container(
                                      padding: const EdgeInsets.symmetric(
                                          horizontal: 10, vertical: 5),
                                      decoration: BoxDecoration(
                                          color: reasonCtrl.text == cat
                                              ? const Color(0xFF0EA5E9)
                                                  .withOpacity(0.12)
                                              : const Color(0xFFF1F5F9),
                                          borderRadius:
                                              BorderRadius.circular(20),
                                          border: Border.all(
                                              color: reasonCtrl.text == cat
                                                  ? const Color(0xFF0EA5E9)
                                                  : Colors.transparent)),
                                      child: Text(cat,
                                          style: TextStyle(
                                              fontSize: 11,
                                              fontWeight: FontWeight.w600,
                                              color: reasonCtrl.text == cat
                                                  ? const Color(0xFF0EA5E9)
                                                  : const Color(0xFF334155))),
                                    ),
                                  ))
                              .toList()),
                      const SizedBox(height: 10),
                      TextField(
                          controller: reasonCtrl,
                          maxLines: 2,
                          decoration: InputDecoration(
                              labelText: 'Reason / description',
                              border: OutlineInputBorder(
                                  borderRadius: BorderRadius.circular(10)))),
                      const SizedBox(height: 10),
                      Row(children: [
                        const Text('Points: ',
                            style: TextStyle(
                                fontWeight: FontWeight.w700, fontSize: 13)),
                        const SizedBox(width: 8),
                        GestureDetector(
                            onTap: () => ss(
                                () => pts = (pts - 5).clamp(-50, 50).toInt()),
                            child: const Icon(Icons.remove_circle_outline,
                                color: Colors.red)),
                        const SizedBox(width: 8),
                        Text('${pts > 0 ? "+" : ""}$pts',
                            style: TextStyle(
                                fontWeight: FontWeight.w900,
                                fontSize: 16,
                                color: pts >= 0 ? Colors.green : Colors.red)),
                        const SizedBox(width: 8),
                        GestureDetector(
                            onTap: () => ss(
                                () => pts = (pts + 5).clamp(-50, 50).toInt()),
                            child: const Icon(Icons.add_circle_outline,
                                color: Colors.green)),
                      ]),
                    ])),
                actions: [
                  TextButton(
                      onPressed: () => Navigator.pop(ctx),
                      child: const Text('Cancel')),
                  ElevatedButton(
                      style: ElevatedButton.styleFrom(
                          backgroundColor: const Color(0xFF0EA5E9),
                          foregroundColor: Colors.white,
                          shape: RoundedRectangleBorder(
                              borderRadius: BorderRadius.circular(10))),
                      onPressed: () {
                        if (reasonCtrl.text.trim().isEmpty) return;
                        FirebaseService.submitComplaint(
                          reporterUid: FirebaseService.currentUser?.uid ?? '',
                          reporterName: userProfile.companyName.isNotEmpty
                              ? userProfile.companyName
                              : userProfile.phone,
                          targetName: d.name,
                          targetType: 'driver',
                          targetId: d.id,
                          reason: reasonCtrl.text.trim(),
                          suggestedPoints: pts,
                        ).then((_) {
                          Navigator.pop(ctx);
                          ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
                              content: Text(
                                  '✅ Report submitted — admin will review and apply points'),
                              backgroundColor: Color(0xFF0EA5E9),
                              behavior: SnackBarBehavior.floating));
                        });
                      },
                      child: const Text('Submit to Admin',
                          style: TextStyle(fontWeight: FontWeight.w800))),
                ],
              ),
            ));
  }

  Future<void> _uploadDriverDoc(
      Driver driver, DriverDoc doc, DocUploadMethod method) async {
    String? pickedFile;
    String? pickedPath;
    String pickedMime = 'image/jpeg';
    Map<String, String> ocrData = {};
    try {
      if (method == DocUploadMethod.camera) {
        final xfile = await ImagePicker().pickImage(
            source: ImageSource.camera,
            imageQuality: 95,
            maxWidth: 2048,
            maxHeight: 2048,
            preferredCameraDevice: CameraDevice.rear);
        if (xfile != null) {
          pickedFile = xfile.name;
          pickedPath = xfile.path;
          pickedMime = 'image/jpeg';
        }
      } else {
        final res = await FilePicker.pickFiles(
            type: FileType.custom,
            allowedExtensions: ['pdf', 'jpg', 'jpeg', 'png'],
            allowMultiple: false,
            withData: false);
        if (res != null && res.files.isNotEmpty) {
          pickedFile = res.files.single.name;
          pickedPath = res.files.single.path;
          pickedMime = (pickedFile ?? '').endsWith('.pdf')
              ? 'application/pdf'
              : 'image/jpeg';
        }
      }
    } catch (e) {
      pickedFile = null;
    }

    // Run OCR on the image
    if (pickedPath != null && pickedMime.startsWith('image') && mounted) {
      ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
          content: Row(children: [
            SizedBox(
                width: 16,
                height: 16,
                child: CircularProgressIndicator(
                    strokeWidth: 2, color: Color(0xFF0F172A))),
            SizedBox(width: 12),
            Text("Reading document details...")
          ]),
          backgroundColor: Colors.indigo,
          behavior: SnackBarBehavior.floating,
          duration: Duration(seconds: 6)));
      ocrData = await FirebaseService.extractDocumentText(pickedPath);
      if (mounted) ScaffoldMessenger.of(context).hideCurrentSnackBar();
    }
    if (!mounted) return;
    // Pre-fill from OCR
    String ocrDocNum = '';
    if (doc.type == 'aadhaar' && ocrData['aadhaarNo'] != null) {
      ocrDocNum = ocrData['aadhaarNo']!;
    }
    if (doc.type == 'dl' && ocrData['dlNo'] != null) {
      ocrDocNum = ocrData['dlNo']!;
    }
    final numCtrl = TextEditingController(
        text: ocrDocNum.isNotEmpty ? ocrDocNum : doc.docNumber);
    final expCtrl = TextEditingController(text: ocrData['expiryDate'] ?? '');
    showDialog(
        context: context,
        builder: (c) => StatefulBuilder(
            builder: (c, ss) => AlertDialog(
                  shape: RoundedRectangleBorder(
                      borderRadius: BorderRadius.circular(18)),
                  title: Row(children: [
                    Icon(
                        pickedFile != null
                            ? Icons.check_circle
                            : Icons.edit_document,
                        color: pickedFile != null
                            ? Colors.green
                            : const Color(0xFFF6FAFF),
                        size: 22),
                    const SizedBox(width: 8),
                    Flexible(
                        child: Text("Upload ${doc.label}",
                            overflow: TextOverflow.ellipsis,
                            style: const TextStyle(
                                fontSize: 15, fontWeight: FontWeight.w800))),
                  ]),
                  content: Column(
                      mainAxisSize: MainAxisSize.min,
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: [
                        if (pickedFile != null)
                          Container(
                              margin: const EdgeInsets.only(bottom: 12),
                              padding: const EdgeInsets.all(10),
                              decoration: BoxDecoration(
                                  color: Colors.green.withOpacity(0.08),
                                  borderRadius: BorderRadius.circular(10),
                                  border:
                                      Border.all(color: Colors.green.shade200)),
                              child: Row(children: [
                                const Icon(Icons.attach_file,
                                    color: Colors.green, size: 18),
                                const SizedBox(width: 8),
                                Flexible(
                                    child: Text(pickedFile,
                                        style: const TextStyle(
                                            color: Colors.green,
                                            fontWeight: FontWeight.w700,
                                            fontSize: 12),
                                        overflow: TextOverflow.ellipsis)),
                              ]))
                        else
                          Container(
                              margin: const EdgeInsets.only(bottom: 12),
                              padding: const EdgeInsets.all(10),
                              decoration: BoxDecoration(
                                  color: Colors.orange.withOpacity(0.08),
                                  borderRadius: BorderRadius.circular(10)),
                              child: const Text(
                                  "Enter details manually or try again",
                                  style: TextStyle(
                                      color: Colors.orange, fontSize: 12))),
                        TextField(
                            style: const TextStyle(
                                color: Color(0xFF0F172A),
                                fontSize: 14,
                                fontWeight: FontWeight.w500),
                            controller: numCtrl,
                            decoration: InputDecoration(
                                labelText: doc.type == 'aadhaar'
                                    ? "Aadhaar Number (12 digits)"
                                    : doc.type == 'dl'
                                        ? "DL Number"
                                        : "Reference Number",
                                prefixIcon: Icon(
                                    doc.type == 'aadhaar'
                                        ? Icons.fingerprint
                                        : doc.type == 'dl'
                                            ? Icons.card_membership
                                            : Icons.numbers,
                                    size: 18),
                                filled: true,
                                fillColor: const Color(0xFFF6FAFF),
                                labelStyle: const TextStyle(
                                    color: Color(0xFF0F172A),
                                    fontSize: 13,
                                    fontWeight: FontWeight.w500),
                                floatingLabelStyle: const TextStyle(
                                    color: Color(0xFF0EA5E9),
                                    fontWeight: FontWeight.w800,
                                    fontSize: 12),
                                border: OutlineInputBorder(
                                    borderRadius: BorderRadius.circular(10),
                                    borderSide: const BorderSide(
                                        color: Color(0xFF0EA5E9))),
                                enabledBorder: OutlineInputBorder(
                                    borderRadius: BorderRadius.circular(10),
                                    borderSide: const BorderSide(
                                        color: Color(0xFF0EA5E9))),
                                focusedBorder: OutlineInputBorder(
                                    borderRadius: BorderRadius.circular(10),
                                    borderSide: const BorderSide(
                                        color: Color(0xFF0EA5E9), width: 2)))),
                        if (doc.type != 'photo') ...[
                          const SizedBox(height: 10),
                          TextField(
                              style: const TextStyle(
                                  color: Color(0xFF0F172A),
                                  fontSize: 14,
                                  fontWeight: FontWeight.w500),
                              controller: expCtrl,
                              decoration: InputDecoration(
                                  labelText: "Expiry Date (DD/MM/YYYY)",
                                  hintText: "e.g. 31/12/2028",
                                  prefixIcon: const Icon(Icons.calendar_today,
                                      size: 18),
                                  filled: true,
                                  fillColor: const Color(0xFFF6FAFF),
                                  labelStyle: const TextStyle(
                                      color: Color(0xFF0F172A),
                                      fontSize: 13,
                                      fontWeight: FontWeight.w500),
                                  floatingLabelStyle: const TextStyle(
                                      color: Color(0xFF0EA5E9),
                                      fontWeight: FontWeight.w800,
                                      fontSize: 12),
                                  border: OutlineInputBorder(
                                      borderRadius: BorderRadius.circular(10),
                                      borderSide: const BorderSide(
                                          color: Color(0xFF0EA5E9))),
                                  enabledBorder: OutlineInputBorder(
                                      borderRadius: BorderRadius.circular(10),
                                      borderSide: const BorderSide(
                                          color: Color(0xFF0EA5E9))),
                                  focusedBorder: OutlineInputBorder(
                                      borderRadius: BorderRadius.circular(10),
                                      borderSide: const BorderSide(
                                          color: Color(0xFF0EA5E9),
                                          width: 2)))),
                        ],
                      ]),
                  actions: [
                    TextButton(
                        onPressed: () => Navigator.pop(c),
                        child: const Text("Cancel")),
                    ElevatedButton.icon(
                        style: ElevatedButton.styleFrom(
                            backgroundColor: const Color(0xFFF6FAFF),
                            shape: RoundedRectangleBorder(
                                borderRadius: BorderRadius.circular(10))),
                        icon: const Icon(Icons.check,
                            color: Color(0xFF0F172A), size: 16),
                        label: const Text("Save",
                            style: TextStyle(
                                color: Color(0xFF0F172A),
                                fontWeight: FontWeight.bold)),
                        onPressed: () {
                          setState(() {
                            doc.isUploaded = true;
                            doc.docNumber = numCtrl.text;
                            doc.uploadDate =
                                "${DateTime.now().day}/${DateTime.now().month}/${DateTime.now().year}";
                            if (expCtrl.text.isNotEmpty) {
                              doc.expiryDate = expCtrl.text;
                            }
                            if (pickedFile != null) {
                              doc.fileName = pickedFile;
                            }
                            if (pickedPath != null) {
                              doc.filePath = pickedPath;
                              doc.mimeType = pickedMime;
                            }
                            if (doc.type == 'aadhaar' &&
                                numCtrl.text.isNotEmpty) {
                              driver.aadharNum = numCtrl.text;
                            }
                            if (doc.type == 'dl' && numCtrl.text.isNotEmpty) {
                              driver.dlNum = numCtrl.text;
                            }
                          });
                          _save();
                          Navigator.pop(c);
                          ScaffoldMessenger.of(context).showSnackBar(SnackBar(
                              backgroundColor: Colors.green,
                              behavior: SnackBarBehavior.floating,
                              content: Text(
                                  "OK ${doc.label} ${pickedFile != null ? 'uploaded' : 'recorded'}!")));
                        }),
                  ],
                )));
  }

