  List<Widget> _buildTabScreens() {
    if (_isDriver) {
      // Driver: minimal clean dashboard — only what a driver needs
      return [_buildDriverDash(), _buildKhata()];
    }
    if (_isConsignor) {
      // Consignor: finds loads, dispatches, views khata — no fleet/driver mgmt
      return [_buildDash(), _buildFindLoad(), _buildPostLoad(), _buildKhata()];
    }
    // Fleet owner: full access
    return [
      _buildDash(),
      _buildFindLoad(),
      _buildPostLoad(),
      _buildKhata(),
      _buildFleet(),
      _buildDrivers()
    ];
  }

