  @override
  void initState() {
    super.initState();
    _ctrl = widget.controller ?? TextEditingController();
    _focus.addListener(() {
      if (!_focus.hasFocus) {
        Future.delayed(const Duration(milliseconds: 200), _rmOverlay);
      }
    });
  }

  @override
  void dispose() {
    _rmOverlay();
    _deb?.cancel();
    _focus.dispose();
    if (widget.controller == null) _ctrl.dispose();
    super.dispose();
  }

  Future<void> _search(String q) async {
    if (_selecting) return;
    if (q.length < 2) {
      _rmOverlay();
      setState(() {
        _results = [];
        _loading = false;
      });
      return;
    }
    setState(() => _loading = true);
    // ── 1. Google Places Autocomplete ──────────────────────────────
    List<_PlaceResult> apiResults = [];
    try {
      final url = Uri.parse(
        'https://maps.googleapis.com/maps/api/place/autocomplete/json'
        '?input=${Uri.encodeComponent(q)}'
        '&components=country:in'
        '&types=establishment'
        '&language=en'
        '&key=${AppConfig.googleMapsApiKey}',
      );
      final res = await http.get(url).timeout(const Duration(seconds: 6));
      if (res.statusCode == 200) {
        final data = jsonDecode(res.body);
        if ((data['status'] as String?) == 'OK') {
          final preds = data['predictions'] as List;
          apiResults = preds.take(8).map((p) {
            final desc = p['description'] as String? ?? '';
            final terms = p['terms'] as List? ?? [];
            final name = terms.isNotEmpty
                ? (terms[0]['value'] as String? ?? desc.split(',').first.trim())
                : desc.split(',').first.trim();
            final addr = terms.length > 1
                ? terms
                    .skip(1)
                    .map((t) => t['value'] as String? ?? '')
                    .where((s) => s.isNotEmpty)
                    .join(', ')
                : '';
            return _PlaceResult(
                name: name,
                address: addr,
                placeId: p['place_id'] as String? ?? '',
                fromApi: true);
          }).toList();
        }
      }
    } catch (_) {}
    // ── 2. Offline fallback ────────────────────────────────────────
    if (apiResults.isEmpty) {
      final ql = q.toLowerCase();
      apiResults = _kFallback
          .where((f) => (f['n']!.toLowerCase().contains(ql) ||
              (f['a'] ?? '').toLowerCase().contains(ql)))
          .take(8)
          .map((f) => _PlaceResult(
              name: f['n']!,
              address: f['a'] ?? '',
              placeId: '',
              fromApi: false))
          .toList();
    }
    if (!mounted) return;
    _results = apiResults;
    setState(() => _loading = false);
    if (_results.isEmpty) {
      _rmOverlay();
      return;
    }
    _rmOverlay();
    _showOverlay();
  }

  void _onChange(String v) {
    if (_selecting) return;
    _deb?.cancel();
    _deb = Timer(const Duration(milliseconds: 380), () => _search(v.trim()));
    setState(() {}); // redraw suffix icon
  }

  void _showOverlay() {
    final box = context.findRenderObject() as RenderBox?;
    if (box == null) return;
    _overlay = OverlayEntry(builder: (_) {
      return Positioned(
        width: box.size.width,
        child: CompositedTransformFollower(
          link: _link,
          showWhenUnlinked: false,
          offset: Offset(0, box.size.height + 6),
          child: Material(
            elevation: 16,
            shadowColor: Colors.black26,
            borderRadius: BorderRadius.circular(16),
            child: Container(
              constraints: const BoxConstraints(maxHeight: 320),
              decoration: BoxDecoration(
                color: Colors.white,
                borderRadius: BorderRadius.circular(16),
                border: Border.all(
                    color: widget.iconColor.withOpacity(0.25), width: 1.5),
              ),
              child: Column(mainAxisSize: MainAxisSize.min, children: [
                // Header
                Container(
                  padding:
                      const EdgeInsets.symmetric(horizontal: 14, vertical: 10),
                  decoration: BoxDecoration(
                    color: widget.iconColor.withOpacity(0.06),
                    borderRadius:
                        const BorderRadius.vertical(top: Radius.circular(15)),
                  ),
                  child: Row(children: [
                    Icon(Icons.location_searching_rounded,
                        color: widget.iconColor, size: 14),
                    const SizedBox(width: 6),
                    Text(
                        '${_results.length} location${_results.length == 1 ? '' : 's'} found',
                        style: TextStyle(
                            color: widget.iconColor,
                            fontSize: 11,
                            fontWeight: FontWeight.w700)),
                    const Spacer(),
                    if (!_results.first.fromApi)
                      Container(
                        padding: const EdgeInsets.symmetric(
                            horizontal: 6, vertical: 2),
