                            horizontal: 6, vertical: 2),
                        decoration: BoxDecoration(
                            color: Colors.green.withOpacity(0.1),
                            borderRadius: BorderRadius.circular(6)),
                        child: const Text('Google Maps Live',
                            style: TextStyle(
                                color: Colors.green,
                                fontSize: 9,
                                fontWeight: FontWeight.w700)),
                      ),
                  ]),
                ),
                // Results list
                Flexible(
                  child: ListView.separated(
                    padding: EdgeInsets.zero,
                    shrinkWrap: true,
                    itemCount: _results.length,
                    separatorBuilder: (_, __) =>
                        Divider(height: 1, color: Colors.grey.shade100),
                    itemBuilder: (_, i) {
                      final r = _results[i];
                      return InkWell(
                        borderRadius: i == _results.length - 1
                            ? const BorderRadius.vertical(
                                bottom: Radius.circular(15))
                            : BorderRadius.zero,
                        onTap: () {
                          _selecting = true;
                          _rmOverlay();
                          _deb?.cancel();
                          _ctrl.text = r.name;
                          widget.onSelected(r.name, r.placeId);
                          _focus.unfocus();
                          setState(() {});
                          Future.delayed(const Duration(milliseconds: 500), () {
                            if (mounted) _selecting = false;
                          });
                        },
                        child: Padding(
                          padding: const EdgeInsets.symmetric(
                              horizontal: 14, vertical: 11),
                          child: Row(children: [
                            // Pin icon
                            Container(
                              width: 38,
                              height: 38,
                              decoration: BoxDecoration(
                                color: widget.iconColor.withOpacity(0.09),
                                borderRadius: BorderRadius.circular(10),
                              ),
                              child: Icon(Icons.factory_rounded,
                                  color: widget.iconColor, size: 18),
                            ),
                            const SizedBox(width: 12),
                            Expanded(
                                child: Column(
                                    crossAxisAlignment:
                                        CrossAxisAlignment.start,
                                    children: [
                                  Text(r.name,
                                      style: const TextStyle(
                                          fontWeight: FontWeight.w800,
                                          fontSize: 13,
                                          color: Color(0xFF0F172A)),
                                      maxLines: 1,
                                      overflow: TextOverflow.ellipsis),
                                  if (r.address.isNotEmpty)
                                    Text(r.address,
                                        style: const TextStyle(
                                            fontSize: 11,
                                            color: Color(0xFF64748B)),
                                        maxLines: 1,
                                        overflow: TextOverflow.ellipsis),
                                ])),
                            Icon(Icons.chevron_right_rounded,
                                color: widget.iconColor.withOpacity(0.5),
                                size: 18),
                          ]),
                        ),
                      );
                    },
                  ),
                ),
                // Footer
                Container(
                  padding:
                      const EdgeInsets.symmetric(horizontal: 14, vertical: 7),
                  decoration: BoxDecoration(
                    color: Colors.grey.shade50,
                    borderRadius: const BorderRadius.vertical(
                        bottom: Radius.circular(15)),
                    border:
                        Border(top: BorderSide(color: Colors.grey.shade100)),
                  ),
                  child: Row(
                      mainAxisAlignment: MainAxisAlignment.center,
                      children: [
                        Image.network(
                            'https://maps.gstatic.com/mapfiles/api-3/images/powered-by-google-on-white3.png',
                            height: 14,
                            errorBuilder: (_, __, ___) =>
                                const SizedBox.shrink()),
                      ]),
                ),
              ]),
            ),
          ),
        ),
      );
    });
    Overlay.of(context).insert(_overlay!);
  }

  void _rmOverlay() {
    _overlay?.remove();
    _overlay = null;
  }

  @override
  Widget build(BuildContext context) {
    final hasValue = _ctrl.text.isNotEmpty;
    return CompositedTransformTarget(
      link: _link,
      child: TextField(
        controller: _ctrl,
        focusNode: _focus,
        onChanged: _onChange,
        style: const TextStyle(
            color: Color(0xFF0F172A),
            fontSize: 14,
            fontWeight: FontWeight.w600),
        decoration: InputDecoration(
          labelText: widget.label,
          hintText: 'Type to search any factory, plant, depot...',
          hintStyle: const TextStyle(color: Color(0xFFB0BEC5), fontSize: 13),
          prefixIcon: _loading
              ? Padding(
                  padding: const EdgeInsets.all(12),
                  child: SizedBox(
                      width: 18,
                      height: 18,
                      child: CircularProgressIndicator(
                          color: widget.iconColor, strokeWidth: 2)))
              : Icon(Icons.factory_rounded, color: widget.iconColor, size: 20),
          suffixIcon: hasValue
              ? IconButton(
                  icon: const Icon(Icons.cancel_rounded,
                      size: 18, color: Color(0xFF94A3B8)),
                  onPressed: () {
                    _ctrl.clear();
                    _rmOverlay();
                    setState(() {
                      _results = [];
                    });
                    widget.onSelected('', '');
                  })
              : null,
          filled: true,
          fillColor: const Color(0xFFF8FAFF),
          labelStyle: TextStyle(
              color: widget.iconColor.withOpacity(0.8),
              fontWeight: FontWeight.w600,
              fontSize: 13),
          floatingLabelStyle: TextStyle(
              color: widget.iconColor,
              fontWeight: FontWeight.w800,
              fontSize: 12),
          contentPadding:
              const EdgeInsets.symmetric(horizontal: 16, vertical: 14),
          border: OutlineInputBorder(
              borderRadius: BorderRadius.circular(12),
              borderSide: BorderSide(color: widget.iconColor.withOpacity(0.3))),
          enabledBorder: OutlineInputBorder(
              borderRadius: BorderRadius.circular(12),
              borderSide: BorderSide(color: widget.iconColor.withOpacity(0.4))),
          focusedBorder: OutlineInputBorder(
              borderRadius: BorderRadius.circular(12),
              borderSide: BorderSide(color: widget.iconColor, width: 2.5)),
        ),
      ),
    );
  }
}

