                    fontWeight: pw.FontWeight.bold,
                    fontSize: 10,
                    color: PdfColor.fromHex('#1D4ED8'))),
            pw.SizedBox(height: 6),
            pw.Table(
              border: pw.TableBorder.all(
                  color: PdfColor.fromHex('#BFDBFE'), width: 0.5),
              columnWidths: {
                0: const pw.FlexColumnWidth(1),
