        child: pw.Column(
            crossAxisAlignment: pw.CrossAxisAlignment.start,
            children: [
              pw.Text(label,
                  style: pw.TextStyle(fontSize: 8, color: PdfColors.grey700)),
              pw.SizedBox(height: 3),
              pw.Text(value,
                  style: pw.TextStyle(
                      fontWeight: pw.FontWeight.bold,
                      fontSize: 12,
                      color: color)),
            ]),
      ));

  @override
  Widget build(BuildContext context) {
    final parties = _parties;
    if (parties.isEmpty) {
      return Container(
        padding: const EdgeInsets.all(14),
        decoration: BoxDecoration(
            color: widget.card2Color,
            borderRadius: BorderRadius.circular(12),
            border: Border.all(color: widget.borderColor)),
        child: const Text(
            'No trip data yet. Add trips to generate party statements.',
            style: TextStyle(color: Color(0xFF64748B), fontSize: 13)),
      );
    }
    return Container(
      padding: const EdgeInsets.all(14),
      decoration: BoxDecoration(
          color: widget.cardColor,
          borderRadius: BorderRadius.circular(14),
          border: Border.all(color: widget.borderColor)),
      child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
        const Text(
            'Select party to generate a PDF statement of all trips and outstanding:',
            style: TextStyle(color: Color(0xFF64748B), fontSize: 12)),
        const SizedBox(height: 10),
        DropdownButtonFormField<String>(
          value: _selectedParty,
          style: const TextStyle(
              color: Color(0xFF0F172A),
              fontSize: 14,
              fontWeight: FontWeight.w600),
          decoration: InputDecoration(
            labelText: 'Select Party / Consignor',
            filled: true,
            fillColor: widget.card2Color,
            labelStyle: const TextStyle(color: Color(0xFF64748B), fontSize: 13),
            border: OutlineInputBorder(
                borderRadius: BorderRadius.circular(10),
                borderSide: BorderSide(color: widget.borderColor)),
            enabledBorder: OutlineInputBorder(
                borderRadius: BorderRadius.circular(10),
                borderSide: BorderSide(color: widget.borderColor)),
            focusedBorder: OutlineInputBorder(
                borderRadius: BorderRadius.circular(10),
                borderSide: BorderSide(color: widget.accentColor, width: 2)),
            prefixIcon: Icon(Icons.business_rounded,
                color: widget.purpleColor, size: 18),
          ),
          items: parties
              .map((p) => DropdownMenuItem(value: p, child: Text(p)))
              .toList(),
          onChanged: (v) => setState(() => _selectedParty = v),
        ),
        const SizedBox(height: 12),
        SizedBox(
          width: double.infinity,
          child: GestureDetector(
            onTap: (_selectedParty == null || _generating)
                ? null
                : _generateStatement,
            child: Container(
              padding: const EdgeInsets.symmetric(vertical: 12),
              decoration: BoxDecoration(
                color: (_selectedParty == null || _generating)
                    ? const Color(0xFF94A3B8)
                    : widget.purpleColor,
                borderRadius: BorderRadius.circular(10),
              ),
              child:
                  Row(mainAxisAlignment: MainAxisAlignment.center, children: [
                if (_generating)
                  const SizedBox(
                      width: 16,
                      height: 16,
                      child: CircularProgressIndicator(
                          color: Colors.white, strokeWidth: 2))
                else
                  const Icon(Icons.picture_as_pdf_rounded,
                      color: Colors.white, size: 18),
                const SizedBox(width: 8),
                Text(
                    _generating
                        ? 'Generating...'
                        : 'Generate Party Statement PDF',
                    style: const TextStyle(
                        color: Colors.white,
                        fontWeight: FontWeight.w800,
                        fontSize: 14)),
              ]),
            ),
          ),
        ),
      ]),
    );
  }
}

// ================================================================
// LANGUAGE SELECTOR WIDGET
// ================================================================
class _LanguageSelectorWidget extends StatefulWidget {
  final VoidCallback onUpdate;
  const _LanguageSelectorWidget({required this.onUpdate});
  @override
  State<_LanguageSelectorWidget> createState() =>
      _LanguageSelectorWidgetState();
}

class _LanguageSelectorWidgetState extends State<_LanguageSelectorWidget> {
  String _selected = 'en';

  @override
  void initState() {
    super.initState();
    SharedPreferences.getInstance().then((p) {
      if (mounted)
        setState(() => _selected = p.getString('rm_language') ?? 'en');
    });
  }

  @override
  Widget build(BuildContext context) {
    const border = OutlineInputBorder(
        borderRadius: BorderRadius.all(Radius.circular(12)),
        borderSide: BorderSide(color: Color(0xFFBFE7FF)));
    return Container(
      padding: const EdgeInsets.all(14),
      decoration: BoxDecoration(
          color: Colors.white,
          borderRadius: BorderRadius.circular(14),
          border: Border.all(color: const Color(0xFFBFE7FF))),
      child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
        const Text(
            'Select your preferred language for the app interface. Applies to labels, placeholders and AI copilot responses.',
            style:
                TextStyle(color: Color(0xFF64748B), fontSize: 12, height: 1.5)),
        const SizedBox(height: 12),
        Wrap(
            spacing: 8,
            runSpacing: 8,
            children: AppConfig.supportedLanguages.entries.map((e) {
              final isSelected = _selected == e.key;
              return GestureDetector(
                onTap: () async {
                  setState(() => _selected = e.key);
                  final p = await SharedPreferences.getInstance();
                  await p.setString('rm_language', e.key);
                  widget.onUpdate();
                  if (mounted) {
                    ScaffoldMessenger.of(context).showSnackBar(SnackBar(
                        content: Text('Language set to ${e.value}'),
                        backgroundColor: const Color(0xFF0EA5E9),
                        behavior: SnackBarBehavior.floating));
                  }
                },
                child: AnimatedContainer(
                  duration: const Duration(milliseconds: 150),
                  padding:
                      const EdgeInsets.symmetric(horizontal: 14, vertical: 8),
                  decoration: BoxDecoration(
                      color: isSelected
                          ? const Color(0xFF0EA5E9).withOpacity(0.12)
                          : const Color(0xFFEFF6FF),
                      borderRadius: BorderRadius.circular(20),
                      border: Border.all(
                          color: isSelected
                              ? const Color(0xFF0EA5E9)
                              : const Color(0xFFBFE7FF),
                          width: isSelected ? 1.5 : 1)),
                  child: Row(mainAxisSize: MainAxisSize.min, children: [
                    if (isSelected) ...[
                      const Icon(Icons.check_rounded,
                          size: 13, color: Color(0xFF0EA5E9)),
                      const SizedBox(width: 4),
                    ],
                    Text(e.value,
                        style: TextStyle(
                            color: isSelected
                                ? const Color(0xFF0EA5E9)
                                : const Color(0xFF334155),
                            fontWeight:
                                isSelected ? FontWeight.w800 : FontWeight.w500,
                            fontSize: 12)),
                  ]),
                ),
              );
            }).toList()),
        const SizedBox(height: 10),
        Container(
          padding: const EdgeInsets.all(9),
          decoration: BoxDecoration(
              color: const Color(0xFFEFF6FF),
              borderRadius: BorderRadius.circular(8)),
          child: const Row(children: [
            Icon(Icons.info_outline_rounded,
                size: 13, color: Color(0xFF0EA5E9)),
            SizedBox(width: 6),
            Expanded(
                child: Text(
                    'AI Copilot automatically responds in the language you write in — this setting affects app UI labels.',
                    style: TextStyle(
                        color: Color(0xFF64748B), fontSize: 11, height: 1.4))),
          ]),
        ),
      ]),
    );
  }
}

// ================================================================
// ADMIN NOTIFICATION COMPOSER WIDGET
// Sends real-time push notifications to all users via Firestore broadcasts
// ================================================================
class _AdminNotifComposer extends StatefulWidget {
  @override
  State<_AdminNotifComposer> createState() => _AdminNotifComposerState();
}

class _AdminNotifComposerState extends State<_AdminNotifComposer> {
  final _titleCtrl = TextEditingController();
  final _bodyCtrl = TextEditingController();
  String _target = 'all_users';
  bool _sending = false;
  bool _sent = false;

  static const _card = Color(0xFFFFFFFF);
  static const _card2 = Color(0xFFEFF6FF);
  static const _border = Color(0xFFBFE7FF);
  static const _accent = Color(0xFF0EA5E9);
  static const _green = Color(0xFF10B981);

  @override
  void dispose() {
    _titleCtrl.dispose();
    _bodyCtrl.dispose();
    super.dispose();
  }

  Future<void> _send() async {
    if (_titleCtrl.text.trim().isEmpty || _bodyCtrl.text.trim().isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
        content: Text('Title and message are required'),
        backgroundColor: Colors.red,
      ));
      return;
    }
    setState(() {
      _sending = true;
      _sent = false;
    });
    final ok = await FirebaseService.adminBroadcastNotification(
      title: _titleCtrl.text.trim(),
      body: _bodyCtrl.text.trim(),
      target: _target,
    );
    if (mounted) {
      setState(() {
        _sending = false;
        _sent = ok;
      });
      if (ok) {
        _titleCtrl.clear();
        _bodyCtrl.clear();
        ScaffoldMessenger.of(context).showSnackBar(SnackBar(
          backgroundColor: _green,
          behavior: SnackBarBehavior.floating,
          content: Row(children: const [
            Icon(Icons.check_circle, color: Colors.white, size: 18),
            SizedBox(width: 8),
            Text('Notification sent to all devices!',
                style: TextStyle(
                    color: Colors.white, fontWeight: FontWeight.w700)),
          ]),
        ));
      } else {
        ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
          backgroundColor: Colors.red,
          behavior: SnackBarBehavior.floating,
          content: Text('Send failed — check Firebase connection'),
        ));
      }
    }
  }

  @override
  Widget build(BuildContext context) {
    const inputBorder = OutlineInputBorder(
      borderRadius: BorderRadius.all(Radius.circular(12)),
      borderSide: BorderSide(color: Color(0xFFBFE7FF)),
    );
    const focusBorder = OutlineInputBorder(
      borderRadius: BorderRadius.all(Radius.circular(12)),
      borderSide: BorderSide(color: Color(0xFF0EA5E9), width: 2),
    );
    const labelStyle = TextStyle(
        color: Color(0xFF64748B), fontSize: 13, fontWeight: FontWeight.w500);
    const floatingStyle = TextStyle(
        color: Color(0xFF0EA5E9), fontWeight: FontWeight.w700, fontSize: 12);

    return Container(
      padding: const EdgeInsets.all(16),
      decoration: BoxDecoration(
        color: _card,
        borderRadius: BorderRadius.circular(16),
        border: Border.all(color: _border),
      ),
      child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
        // Target selector
        Row(children: [
          const Text('Target:',
              style: TextStyle(
                  color: Color(0xFF0F172A),
                  fontWeight: FontWeight.w700,
                  fontSize: 13)),
          const SizedBox(width: 10),
          ...[
            ('all_users', 'All Users', Icons.people_rounded),
            ('paid_tier', 'Paid Only', Icons.workspace_premium_rounded),
          ].map((t) => GestureDetector(
                onTap: () => setState(() => _target = t.$1),
                child: AnimatedContainer(
                  duration: const Duration(milliseconds: 150),
                  margin: const EdgeInsets.only(right: 8),
                  padding:
                      const EdgeInsets.symmetric(horizontal: 12, vertical: 6),
                  decoration: BoxDecoration(
                    color: _target == t.$1 ? _accent.withOpacity(0.15) : _card2,
                    borderRadius: BorderRadius.circular(20),
                    border: Border.all(
                      color: _target == t.$1 ? _accent : _border,
                      width: _target == t.$1 ? 1.5 : 1,
                    ),
                  ),
                  child: Row(mainAxisSize: MainAxisSize.min, children: [
                    Icon(t.$3,
                        size: 13,
                        color: _target == t.$1
                            ? _accent
                            : const Color(0xFF64748B)),
                    const SizedBox(width: 5),
                    Text(t.$2,
                        style: TextStyle(
                          color: _target == t.$1
                              ? _accent
                              : const Color(0xFF64748B),
                          fontWeight: _target == t.$1
                              ? FontWeight.w800
                              : FontWeight.w500,
                          fontSize: 12,
                        )),
                  ]),
                ),
              )),
        ]),
        const SizedBox(height: 12),
        // Title field
        TextField(
          controller: _titleCtrl,
          style: const TextStyle(
              color: Color(0xFF0F172A),
              fontSize: 14,
              fontWeight: FontWeight.w600),
          decoration: const InputDecoration(
            labelText: 'Notification Title',
            labelStyle: labelStyle,
            floatingLabelStyle: floatingStyle,
            filled: true,
            fillColor: Color(0xFFEFF6FF),
            border: inputBorder,
            enabledBorder: inputBorder,
            focusedBorder: focusBorder,
            prefixIcon:
                Icon(Icons.title_rounded, color: Color(0xFF0EA5E9), size: 18),
          ),
        ),
        const SizedBox(height: 10),
        // Body field
        TextField(
          controller: _bodyCtrl,
          maxLines: 3,
          style: const TextStyle(color: Color(0xFF0F172A), fontSize: 13),
          decoration: const InputDecoration(
            labelText: 'Message',
            labelStyle: labelStyle,
            floatingLabelStyle: floatingStyle,
            filled: true,
            fillColor: Color(0xFFEFF6FF),
            border: inputBorder,
            enabledBorder: inputBorder,
            focusedBorder: focusBorder,
            prefixIcon: Padding(
              padding: EdgeInsets.only(bottom: 48),
              child: Icon(Icons.message_rounded,
                  color: Color(0xFF0EA5E9), size: 18),
            ),
          ),
        ),
        const SizedBox(height: 12),
        // Send button
        SizedBox(
          width: double.infinity,
          child: GestureDetector(
            onTap: _sending ? null : _send,
            child: AnimatedContainer(
              duration: const Duration(milliseconds: 200),
              padding: const EdgeInsets.symmetric(vertical: 14),
              decoration: BoxDecoration(
                gradient: LinearGradient(
                  colors: _sending
                      ? [Colors.grey.shade400, Colors.grey.shade500]
                      : [const Color(0xFF0EA5E9), const Color(0xFF0369A1)],
                ),
                borderRadius: BorderRadius.circular(12),
                boxShadow: _sending
                    ? []
                    : [
                        BoxShadow(
                          color: const Color(0xFF0EA5E9).withOpacity(0.4),
                          blurRadius: 12,
                          offset: const Offset(0, 4),
                        ),
                      ],
              ),
              child:
                  Row(mainAxisAlignment: MainAxisAlignment.center, children: [
                if (_sending)
                  const SizedBox(
                      width: 18,
                      height: 18,
                      child: CircularProgressIndicator(
                          color: Colors.white, strokeWidth: 2))
                else
                  const Icon(Icons.send_rounded, color: Colors.white, size: 18),
                const SizedBox(width: 8),
                Text(
                  _sending
                      ? 'Sending...'
                      : '  Send Notification to All Devices',
                  style: const TextStyle(
                    color: Colors.white,
                    fontWeight: FontWeight.w800,
                    fontSize: 14,
                    letterSpacing: 0.3,
                  ),
                ),
              ]),
            ),
          ),
        ),
        // Info note
        const SizedBox(height: 10),
        Container(
          padding: const EdgeInsets.all(10),
          decoration: BoxDecoration(
            color: _accent.withOpacity(0.07),
            borderRadius: BorderRadius.circular(10),
            border: Border.all(color: _accent.withOpacity(0.2)),
          ),
          child: const Row(children: [
            Icon(Icons.info_outline_rounded,
                color: Color(0xFF0EA5E9), size: 15),
            SizedBox(width: 8),
            Expanded(
                child: Text(
              'Notifications appear instantly on all connected devices as in-app banners. '
              'For true FCM push (when app is closed), set up a Cloud Function watching the adminNotifications collection.',
              style: TextStyle(
                  color: Color(0xFF64748B), fontSize: 11, height: 1.4),
            )),
          ]),
        ),
      ]),
    );
  }
}

class KredXScreen extends StatefulWidget {
  final List<TripLedger> ledgers;
  final List<KredXApplication> kredxApps;
  final Function(KredXApplication) onApply;
  final VoidCallback onUpdate;
  const KredXScreen(
      {super.key,
      required this.ledgers,
      required this.kredxApps,
      required this.onApply,
      required this.onUpdate});
  @override
  State<KredXScreen> createState() => _KredXScreenState();
}

class _KredXScreenState extends State<KredXScreen>
    with SingleTickerProviderStateMixin {
  late TabController _tabs;
  @override
  void initState() {
    super.initState();
    _tabs = TabController(length: 2, vsync: this);
  }

  @override
  void dispose() {
    _tabs.dispose();
    super.dispose();
  }

  List<TripLedger> get _effectiveLedgers {
    final currentName = FirebaseService.currentUser?.displayName ?? '';
    if (currentName.isNotEmpty) {
      final filtered = widget.ledgers
          .where((l) => l.driverName != null && l.driverName == currentName)
          .toList();
      return filtered.isNotEmpty ? filtered : widget.ledgers;
    }
    return widget.ledgers;
  }

  List<TripLedger> get eligible => _effectiveLedgers
      .where((l) =>
          l.partyPending >= 5000 &&
          !widget.kredxApps.any((a) => a.invoiceLedgerId == l.id))
      .toList();
  Widget _kr(String l, String v, {bool b = false}) => Padding(
      padding: const EdgeInsets.symmetric(vertical: 4),
      child: Row(mainAxisAlignment: MainAxisAlignment.spaceBetween, children: [
        Text(l,
            style: TextStyle(
                fontWeight: b ? FontWeight.w900 : FontWeight.w600,
                color: Color(0xFFCBD5E1),
                fontSize: 13)),
        Text(v,
            style: TextStyle(
                fontWeight: FontWeight.w900,
                fontSize: b ? 15 : 13,
                color: const Color(0xFF0F172A)))
      ]));
  void _apply(TripLedger ledger) {
    double max = ledger.partyPending * 0.85;
    double req = max;
    int tenure = 30;
    showModalBottomSheet(
        context: context,
        isScrollControlled: true,
        backgroundColor: Colors.transparent,
        builder: (c) => StatefulBuilder(
            builder: (c2, setSt) => Container(
                  decoration: const BoxDecoration(
                      color: Color(0xFFEFF6FF),
                      borderRadius:
                          BorderRadius.vertical(top: Radius.circular(28))),
                  padding: EdgeInsets.only(
                      bottom: MediaQuery.of(c2).viewInsets.bottom,
                      left: 24,
                      right: 24,
                      top: 28),
                  child: SingleChildScrollView(
                      child: Column(
                          crossAxisAlignment: CrossAxisAlignment.start,
