                                    style: TextStyle(
                                        color: Colors.grey, fontSize: 12))
                              ])
                        ]),
                        const SizedBox(height: 22),
                        Container(
                            padding: const EdgeInsets.all(14),
                            decoration: BoxDecoration(
                                color: Colors.amber.withOpacity(0.08),
                                borderRadius: BorderRadius.circular(12),
                                border: Border.all(color: Colors.amber[200]!)),
                            child: Column(children: [
                              _kr("Party", ledger.partyName),
                              _kr("Invoice",
                                  "Rs.${ledger.partyPending.toStringAsFixed(0)}"),
                              _kr("You Get (85%)",
                                  "Rs.${max.toStringAsFixed(0)}"),
                              _kr("Interest Rate", "1.5% / month")
                            ])),
                        const SizedBox(height: 20),
                        const Text("Request Amount",
                            style: TextStyle(
                                fontWeight: FontWeight.w800,
                                color: Color(0xFF0F172A))),
                        Slider(
                            value: req,
                            min: 5000,
                            max: max > 5000 ? max : 5001,
                            activeColor: Colors.amber[700],
                            label: "Rs.${req.toStringAsFixed(0)}",
                            onChanged: (v) => setSt(() => req = v)),
                        Center(
                            child: Text("Rs.${req.toStringAsFixed(0)}",
                                style: TextStyle(
                                    fontSize: 24,
                                    fontWeight: FontWeight.w900,
                                    color: Colors.amber[700]))),
                        const SizedBox(height: 16),
                        Row(
                            children: [30, 60, 90]
                                .map((t) => Expanded(
                                    child: Padding(
                                        padding: const EdgeInsets.symmetric(
                                            horizontal: 4),
                                        child: GestureDetector(
                                            onTap: () =>
                                                setSt(() => tenure = t),
                                            child: Container(
                                                padding:
                                                    const EdgeInsets.symmetric(
                                                        vertical: 10),
                                                decoration: BoxDecoration(
                                                    color: tenure == t
                                                        ? const Color(
                                                            0xFF0F172A)
                                                        : Colors.grey[100],
                                                    borderRadius:
