                                                child: Center(child: Text("$t Days", style: TextStyle(fontWeight: FontWeight.bold, color: tenure == t ? const Color(0xFFF6FAFF) : Colors.black))))))))
                                .toList()),
                        const SizedBox(height: 14),
                        Container(
                            padding: const EdgeInsets.all(12),
                            decoration: BoxDecoration(
                                color: Colors.green.withOpacity(0.08),
                                borderRadius: BorderRadius.circular(10)),
                            child: Column(children: [
                              _kr("Est. Interest",
                                  "Rs.${(req * 0.015 * (tenure / 30)).toStringAsFixed(0)}"),
                              _kr("Net Disbursed",
                                  "Rs.${(req - req * 0.015 * (tenure / 30)).toStringAsFixed(0)}",
                                  b: true)
                            ])),
                        const SizedBox(height: 18),
                        SizedBox(
                            width: double.infinity,
                            height: 52,
                            child: ElevatedButton(
                                style: ElevatedButton.styleFrom(
                                    backgroundColor: Colors.amber[700],
                                    shape: RoundedRectangleBorder(
                                        borderRadius:
                                            BorderRadius.circular(14))),
                                onPressed: () {
                                  final app = KredXApplication(
                                      id: "KX${math.Random().nextInt(99999)}",
                                      invoiceLedgerId: ledger.id,
                                      partyName: ledger.partyName,
                                      invoiceAmount: ledger.partyPending,
                                      requestedAmount: req,
                                      status: KredXStatus.submitted,
                                      appliedDate:
                                          "${DateTime.now().day}/${DateTime.now().month}/${DateTime.now().year}",
                                      tenureDays: tenure);
                                  widget.onApply(app);
                                  setState(() {});
                                  Navigator.pop(c);
                                  ScaffoldMessenger.of(context).showSnackBar(
                                      const SnackBar(
                                          backgroundColor: Colors.green,
                                          behavior: SnackBarBehavior.floating,
                                          content: Text(
                                              "OK KredX application submitted!")));
                                },
                                child: const Text("Submit to KredX",
                                    style: TextStyle(
                                        color: Color(0xFF0F172A),
                                        fontWeight: FontWeight.bold,
                                        fontSize: 16)))),
                        const SizedBox(height: 24),
                      ])),
                )));
  }

