class SubscriptionScreen extends StatelessWidget {
  final SubscriptionInfo current;
  final Function(SubscriptionTier) onUpgrade;
  const SubscriptionScreen(
      {super.key, required this.current, required this.onUpgrade});
  Widget _feat(bool a, String t) => Padding(
      padding: const EdgeInsets.only(bottom: 8),
      child: Row(children: [
        Icon(a ? Icons.check_circle : Icons.remove_circle_outline,
            size: 16, color: a ? const Color(0xFF0EA5E9) : Color(0x240F766E)),
        const SizedBox(width: 10),
        Text(t,
            style: TextStyle(
                color: a ? const Color(0xFF0F172A) : Color(0xFF94A3B8),
                fontSize: 13,
                fontWeight: a ? FontWeight.w600 : FontWeight.normal))
      ]));
  Widget _plan(BuildContext ctx, SubscriptionTier tier, String name,
      String price, String period, Color color, List<Widget> feats,
      {bool rec = false}) {
    final isCur = current.tier == tier;
    return Container(
        decoration: BoxDecoration(
            color: Colors.white,
            borderRadius: BorderRadius.circular(20),
            border: Border.all(
                color: isCur ? color : color.withOpacity(0.35),
                width: isCur ? 2.5 : 1.5),
            boxShadow: isCur
                ? [
                    BoxShadow(
                        color: color.withOpacity(0.2),
                        blurRadius: 16,
                        offset: const Offset(0, 6))
                  ]
                : []),
        child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
          Container(
              padding: const EdgeInsets.all(18),
              decoration: BoxDecoration(
                  gradient: LinearGradient(
                      colors: [color, color.withOpacity(0.8)],
                      begin: Alignment.topLeft,
                      end: Alignment.bottomRight),
                  borderRadius:
                      const BorderRadius.vertical(top: Radius.circular(18))),
              child: Row(children: [
                Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                  Row(children: [
                    Text(name,
                        style: const TextStyle(
                            color: Colors.white,
                            fontWeight: FontWeight.w900,
                            fontSize: 20)),
                    if (rec) ...[
                      const SizedBox(width: 8),
                      Container(
                          padding: const EdgeInsets.symmetric(
                              horizontal: 8, vertical: 2),
                          decoration: BoxDecoration(
                              color: color,
                              borderRadius: BorderRadius.circular(8)),
                          child: const Text("★ BEST VALUE",
                              style: TextStyle(
                                  color: Colors.white,
                                  fontSize: 9,
                                  fontWeight: FontWeight.w900)))
                    ],
                    if (isCur) ...[
                      const SizedBox(width: 8),
                      Container(
                          padding: const EdgeInsets.symmetric(
                              horizontal: 8, vertical: 2),
                          decoration: BoxDecoration(
                              color: Colors.green.withOpacity(0.2),
                              borderRadius: BorderRadius.circular(8),
                              border: Border.all(color: Colors.green)),
                          child: const Text("✓ ACTIVE",
                              style: TextStyle(
                                  color: Colors.white,
                                  fontSize: 9,
                                  fontWeight: FontWeight.w900)))
                    ]
                  ]),
                  const SizedBox(height: 4),
                  Row(crossAxisAlignment: CrossAxisAlignment.end, children: [
                    Text(price,
                        style: const TextStyle(
                            color: Colors.white,
                            fontWeight: FontWeight.w900,
                            fontSize: 26)),
                    const SizedBox(width: 4),
                    Padding(
                        padding: const EdgeInsets.only(bottom: 4),
                        child: Text(period,
                            style: const TextStyle(
                                color: Color(0xCCFFFFFF), fontSize: 12)))
                  ])
                ])
              ])),
          Padding(
              padding: const EdgeInsets.all(16),
              child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    ...feats,
                    const SizedBox(height: 12),
                    if (!isCur)
                      SizedBox(
                          width: double.infinity,
                          height: 44,
                          child: ElevatedButton(
                              style: ElevatedButton.styleFrom(
                                  backgroundColor: color,
                                  foregroundColor: Colors.white,
                                  shape: RoundedRectangleBorder(
                                      borderRadius: BorderRadius.circular(12))),
                              onPressed: () {
                                onUpgrade(tier);
                                Navigator.pop(ctx);
                                ScaffoldMessenger.of(ctx).showSnackBar(SnackBar(
                                    backgroundColor: color,
                                    behavior: SnackBarBehavior.floating,
                                    content: Text(
                                        "Upgraded to $name! Features unlocked.")));
                              },
                              child: Text(
                                  tier == SubscriptionTier.free
                                      ? "Downgrade to Free"
                                      : "Upgrade to $name",
                                  style: const TextStyle(
                                      color: Color(0xFF0F172A),
                                      fontWeight: FontWeight.bold,
                                      fontSize: 14)))),
                    if (isCur)
                      Container(
                          width: double.infinity,
                          height: 44,
                          decoration: BoxDecoration(
                              color: Colors.green.withOpacity(0.1),
                              borderRadius: BorderRadius.circular(12),
                              border: Border.all(color: Colors.green)),
                          child: const Center(
                              child: Text("OK Your Current Plan",
                                  style: TextStyle(
                                      color: Colors.green,
                                      fontWeight: FontWeight.bold)))),
                  ])),
        ]));
  }

  @override
  Widget build(BuildContext context) => Scaffold(
        backgroundColor: const Color(0xFFF6FAFF),
        appBar: AppBar(
            backgroundColor: const Color(0xFFF6FAFF),
            elevation: 0,
            iconTheme: const IconThemeData(color: Color(0xFF0F172A)),
            title: const Text("Choose Your Plan",
                style: TextStyle(
                    color: Color(0xFF0F172A), fontWeight: FontWeight.w900))),
        body: SingleChildScrollView(
            padding: const EdgeInsets.all(20),
            child: Column(children: [
              Container(
                  padding: const EdgeInsets.all(20),
                  decoration: BoxDecoration(
                      color: Color(0x10334155),
                      borderRadius: BorderRadius.circular(18)),
                  child: Row(children: [
                    Icon(Icons.workspace_premium,
                        color: current.tierColor, size: 32),
                    const SizedBox(width: 14),
                    Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: [
                          const Text("Current Plan",
                              style: TextStyle(
                                  color: Color(0x66334155),
                                  fontSize: 12,
                                  fontWeight: FontWeight.w600)),
                          Text(current.tierName,
                              style: TextStyle(
                                  color: current.tierColor,
                                  fontSize: 22,
                                  fontWeight: FontWeight.w900)),
                          const SizedBox(height: 4),
                          Text("Tap a plan below to upgrade instantly",
                              style: TextStyle(
                                  color: Color(0xFF64748B), fontSize: 11)),
                        ]),
                    const Spacer(),
                    Column(
                        crossAxisAlignment: CrossAxisAlignment.end,
                        children: [
                          Text(
                              "${current.tripsUsedThisMonth}/${current.tier == SubscriptionTier.free ? '10' : 'Unlimited'}",
                              style: const TextStyle(
                                  color: Color(0xFF0F172A),
                                  fontWeight: FontWeight.w900,
                                  fontSize: 18)),
                          const Text("trips this month",
                              style: TextStyle(
                                  color: Color(0x66334155), fontSize: 11))
                        ])
                  ])),
              const SizedBox(height: 20),
              _plan(context, SubscriptionTier.free, "FREE", "Rs.0", "Forever",
                  Colors.grey, [
                _feat(true, "10 trips per month"),
                _feat(true, "Basic ledger & fleet"),
                _feat(true, "Driver roster"),
                _feat(false, "PDF Export (LR & Invoice)"),
                _feat(false, "Live GPS Tracking"),
                _feat(false, "KredX Financing")
              ]),
              const SizedBox(height: 14),
              _plan(context, SubscriptionTier.pro, "PRO", "Rs.799", "/month",
                  Colors.blueAccent, [
                _feat(true, "Unlimited trips"),
                _feat(true, "PDF Export (LR & Invoice)"),
                _feat(true, "Live GPS Tracking"),
                _feat(true, "Route auto-calculator"),
                _feat(true, "Priority support"),
                _feat(false, "KredX Financing")
              ]),
              const SizedBox(height: 14),
              _plan(
                  context,
                  SubscriptionTier.business,
                  "BUSINESS",
                  "Rs.4,999",
                  "/month",
                  Colors.amber.shade700,
                  [
                    _feat(true, "Everything in PRO"),
                    _feat(true, "KredX Invoice Financing"),
                    _feat(true, "Instant advances on invoices"),
                    _feat(true, "3 sub-users"),
                    _feat(true, "Up to 50 vehicles"),
                    _feat(true, "Advanced P&L reports"),
                    _feat(true, "Dedicated account manager")
                  ],
                  rec: true),
              const SizedBox(height: 14),
              _plan(context, SubscriptionTier.enterprise, "ENTERPRISE",
                  "Rs.9,999", "/month", const Color(0xFF0EA5E9), [
                _feat(true, "Everything in BUSINESS"),
                _feat(true, "Unlimited vehicles (50+)"),
                _feat(true, "10 staff / sub-user logins"),
                _feat(true, "Custom company branding"),
                _feat(true, "White-label PDF reports"),
                _feat(true, "API access for integration"),
                _feat(true, "Priority 24x7 phone support"),
                _feat(true, "Onboarding & training session")
              ]),
              const SizedBox(height: 20),
              const Text("All plans include local data backup. Cancel anytime.",
                  textAlign: TextAlign.center,
                  style: TextStyle(color: Color(0x33334155), fontSize: 11)),
            ])),
      );
}

