  @override
  void _updateMapMarkers() {
    if (_mapController == null) return;
    final truckIcon = widget.isLoaded
        ? BitmapDescriptor.defaultMarkerWithHue(BitmapDescriptor.hueGreen)
        : BitmapDescriptor.defaultMarkerWithHue(BitmapDescriptor.hueAzure);
    setState(() {
      _markers = {
        Marker(
          markerId: const MarkerId('truck'),
          position: LatLng(_lat, _lng),
          icon: truckIcon,
          infoWindow: InfoWindow(
            title: widget.vehicleNo,
            snippet: '${_currentSpeedKmh.toStringAsFixed(0)} km/h • $_status',
          ),
        ),
      };
    });
    _mapController?.animateCamera(CameraUpdate.newLatLng(LatLng(_lat, _lng)));
  }

  void initState() {
    super.initState();
    _tabs = TabController(length: 3, vsync: this);
    _pulse = AnimationController(
        vsync: this, duration: const Duration(milliseconds: 1200))
      ..repeat(reverse: true);
    // Calculate ETA: avg HCV speed = 55 km/h on NH, 45 km/h city/state roads
    final km = widget.distanceKm > 0 ? widget.distanceKm : 600.0;
    _eta = (km / 52.0 * 60).round(); // minutes
    _log.insert(0,
        "${_t()} - Dispatched from ${widget.route.split('->').first.trim()}");
    _log.insert(0, "${_t()} - E-Way Bill verified & GPS active");
    _log.insert(0, "${_t()} - Live tracking started");
    _timer = Timer.periodic(const Duration(seconds: 4), (_) {
      if (!mounted) return;
      setState(() {
        if (_prog < 0.97) {
          _prog += 0.008 + math.Random().nextDouble() * 0.008;
          // Simulate GPS movement on real map
          final newLat = _lat + (math.Random().nextDouble() - 0.5) * 0.002;
          final newLng = _lng + math.Random().nextDouble() * 0.003;
          _lat = newLat;
          _lng = newLng;
          _updateMapMarkers();
          // Update simulated speed
          _currentSpeedKmh = _status == 'Driver Break'
              ? 0
              : _status == 'Toll Plaza'
                  ? 12
                  : (42 + math.Random().nextDouble() * 22);
          // ETA recalculated from actual distance
          final remainingKm = widget.distanceKm > 0
              ? widget.distanceKm * (1 - _prog)
              : 600 * (1 - _prog);
          _eta = (remainingKm / 52.0 * 60).round(); // 52 km/h avg
          if (_prog > 0.15 && _prog < 0.17) {
            _status = "Toll Plaza";
            _lastCheckpoint =
                "NH Toll - FASTag ₹${(150 + math.Random().nextInt(200)).toStringAsFixed(0)}";
            _log.insert(0, "${_t()} - FASTag deducted at NH toll");
          }
          if (_prog > 0.35 && _prog < 0.37) {
            _status = "State Border";
            _lastCheckpoint = "State Border Checkpoint";
            _log.insert(0, "${_t()} - Crossed state border, documents checked");
          }
          if (_prog > 0.55 && _prog < 0.57) {
            _status = "Driver Break";
            _lastCheckpoint = "Driver rest stop";
            _log.insert(0, "${_t()} - Rest stop (30 min). ETA revised.");
          }
          if (_prog > 0.75 && _prog < 0.77) {
            _status = "Toll Plaza";
            _lastCheckpoint = "Destination toll";
            _log.insert(0, "${_t()} - FASTag deducted at destination toll");
          }
          if (_prog > 0.88 && _prog < 0.90) {
            _status = "Approaching Destination";
            _log.insert(0, "${_t()} - ~${_fmtEta(_eta)} to destination");
          }
        } else {
          _status = "Arrived";
          if (!_log.first.contains("Arrived")) {
            _log.insert(0, "${_t()} - Vehicle arrived at destination");
          }
        }
      });
    });
  }

  String _t() => DateFormat('HH:mm').format(DateTime.now());

  String _fmtEta(int m) {
    if (m <= 0) return "Arrived";
    int h = m ~/ 60, mn = m % 60;
    return h > 0 ? "${h}h ${mn}m" : "${mn}m";
  }

  // Dark map style matching the app's dark green theme
  static const String _darkMapStyle = '''[
    {"elementType":"geometry","stylers":[{"color":"#0d1f14"}]},
    {"elementType":"labels.text.fill","stylers":[{"color":"#8fbc8f"}]},
    {"elementType":"labels.text.stroke","stylers":[{"color":"#0d1f14"}]},
    {"featureType":"road","elementType":"geometry","stylers":[{"color":"#1a3a2a"}]},
    {"featureType":"road","elementType":"geometry.stroke","stylers":[{"color":"#3d7a52"}]},
    {"featureType":"road.highway","elementType":"geometry","stylers":[{"color":"#243d2e"}]},
    {"featureType":"road.highway","elementType":"geometry.stroke","stylers":[{"color":"#3d7a52"}]},
    {"featureType":"water","elementType":"geometry","stylers":[{"color":"#062e14"}]},
    {"featureType":"poi","elementType":"geometry","stylers":[{"color":"#142b1e"}]},
    {"featureType":"transit","elementType":"geometry","stylers":[{"color":"#1a3a2a"}]}
  ]''';

  @override
  void dispose() {
    _timer?.cancel();
    _pulse.dispose();
    _tabs.dispose();
    _mapController?.dispose();
    super.dispose();
  }

