class _MapGridPainter extends CustomPainter {
  @override
  void paint(Canvas canvas, Size size) {
    // Dark Google-Maps-style grid
    final p = Paint()
      ..color = const Color(0xFF1A3F5C)
      ..strokeWidth = 0.5;
    for (double x = 0; x < size.width; x += 32) {
      canvas.drawLine(Offset(x, 0), Offset(x, size.height), p);
    }
    for (double y = 0; y < size.height; y += 32) {
      canvas.drawLine(Offset(0, y), Offset(size.width, y), p);
    }
    // Major roads
    final rp = Paint()
      ..color = const Color(0xFF1E4F6A)
      ..strokeWidth = 8;
    canvas.drawLine(const Offset(0, 80), Offset(size.width, 80), rp);
    canvas.drawLine(Offset(size.width * 0.35, 0),
        Offset(size.width * 0.35, size.height), rp);
    canvas.drawLine(
        Offset(size.width * 0.7, 0), Offset(size.width * 0.7, size.height), rp);
    // Water body patches
    canvas.drawCircle(
        Offset(size.width * 0.15, size.height * 0.25),
        30,
        Paint()
          ..color = const Color(0xFF0A2540)
          ..style = PaintingStyle.fill);
    canvas.drawCircle(
        Offset(size.width * 0.8, size.height * 0.7),
        20,
        Paint()
          ..color = const Color(0xFF0A2540)
          ..style = PaintingStyle.fill);
    // Park patches
    canvas.drawRect(
        Rect.fromLTWH(size.width * 0.55, size.height * 0.15, 40, 25),
        Paint()
          ..color = const Color(0xFF0D2B1A)
          ..style = PaintingStyle.fill);
  }

  @override
  bool shouldRepaint(covariant CustomPainter _) => false;
}

class _RoadNetworkPainter extends CustomPainter {
  final double progress;
  const _RoadNetworkPainter({required this.progress});
  @override
  void paint(Canvas canvas, Size size) {
    // Diagonal road connections
    final road = Paint()
      ..color = const Color(0xFF1E4F6A)
      ..strokeWidth = 5
      ..style = PaintingStyle.stroke;
    canvas.drawLine(Offset(0, size.height * 0.5),
        Offset(size.width * 0.4, size.height * 0.3), road);
    canvas.drawLine(Offset(size.width * 0.4, size.height * 0.3),
        Offset(size.width, size.height * 0.5), road);
    // Secondary roads
    final sec = Paint()
      ..color = const Color(0xFF162F42)
      ..strokeWidth = 3
      ..style = PaintingStyle.stroke;
    canvas.drawLine(Offset(size.width * 0.2, 0),
        Offset(size.width * 0.5, size.height), sec);
    canvas.drawLine(Offset(size.width * 0.6, 0),
        Offset(size.width * 0.85, size.height), sec);
    // City dots
    void city(double x, double y, bool isPassed) {
      canvas.drawCircle(
          Offset(x, y),
          isPassed ? 5 : 4,
          Paint()
            ..color =
                isPassed ? const Color(0xFF10B981) : const Color(0xFF334155));
      canvas.drawCircle(
          Offset(x, y),
          isPassed ? 10 : 8,
          Paint()
            ..color =
                (isPassed ? const Color(0xFF10B981) : const Color(0xFF334155))
                    .withOpacity(0.2));
    }

    final w = size.width;
    final h = size.height;
    city(w * 0.1, h * 0.4, progress > 0.05);
    city(w * 0.3, h * 0.35, progress > 0.3);
    city(w * 0.55, h * 0.45, progress > 0.55);
    city(w * 0.75, h * 0.38, progress > 0.75);
  }

  @override
  bool shouldRepaint(covariant _RoadNetworkPainter old) =>
      old.progress != progress;
}

// ================================================================
// SHARED EVENTS SCREEN - Cross-user notifications hub
// ================================================================
class SharedEventsScreen extends StatefulWidget {
  final List<TripLedger> ledgers;
  final UserProfile userProfile;
  final VoidCallback? onMarkAllRead;
  const SharedEventsScreen(
      {super.key,
      required this.ledgers,
      required this.userProfile,
      this.onMarkAllRead});
  @override
  State<SharedEventsScreen> createState() => _SharedEventsScreenState();
}

class _SharedEventsScreenState extends State<SharedEventsScreen> {
  String _filter = 'All';
  final Set<String> _readIds = {};

  List<TripLedger> get _filtered {
    final all = widget.ledgers;
    if (_filter == 'All') return all;
    if (_filter == 'Overdue')
      return all.where((l) => l.isPaymentOverdue).toList();
    if (_filter == 'Pending')
      return all
          .where((l) => l.partyPending > 0 && !l.isPaymentOverdue)
          .toList();
    if (_filter == 'Settled')
      return all.where((l) => l.partyPending <= 0).toList();
    return all;
  }

  void _markAllRead() {
    setState(() {
      _readIds.addAll(widget.ledgers.map((l) => l.id));
    });
    widget.onMarkAllRead?.call();
    ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
        content: Text('All notifications marked as read ✓'),
        behavior: SnackBarBehavior.floating,
        backgroundColor: Color(0xFF10B981)));
  }

  @override
  Widget build(BuildContext context) {
    final filtered = _filtered;
    final unreadCount = widget.ledgers
        .where((l) =>
            (l.isPaymentOverdue || l.isDueSoon) && !_readIds.contains(l.id))
        .length;
    return Scaffold(
      backgroundColor: const Color(0xFFF6FAFF),
      appBar: AppBar(
        backgroundColor: const Color(0xFF0F172A),
        iconTheme: const IconThemeData(color: Colors.white),
        title: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            mainAxisSize: MainAxisSize.min,
            children: [
              const Text("Activity Feed",
                  style: TextStyle(
                      color: Colors.white,
                      fontWeight: FontWeight.w900,
                      fontSize: 16)),
              if (unreadCount > 0)
                Text('$unreadCount unread alert${unreadCount > 1 ? "s" : ""}',
                    style: const TextStyle(
                        color: Color(0xFFFCA5A5), fontSize: 11)),
            ]),
        actions: [
          if (unreadCount > 0)
            TextButton.icon(
              onPressed: _markAllRead,
              icon: const Icon(Icons.done_all,
                  color: Color(0xFF86EFAC), size: 16),
              label: const Text('Mark all read',
                  style: TextStyle(
                      color: Color(0xFF86EFAC),
                      fontSize: 12,
                      fontWeight: FontWeight.w700)),
            ),
        ],
      ),
      body: Column(children: [
        // Filter row
        Container(
          color: const Color(0xFF0F172A),
          padding: const EdgeInsets.fromLTRB(16, 0, 16, 12),
          child: SingleChildScrollView(
              scrollDirection: Axis.horizontal,
              child: Row(children: [
                _filterChip('All', Colors.white, widget.ledgers.length),
                const SizedBox(width: 8),
                _filterChip('Overdue', Colors.red,
                    widget.ledgers.where((l) => l.isPaymentOverdue).length),
                const SizedBox(width: 8),
                _filterChip(
                    'Pending',
                    Colors.orange,
                    widget.ledgers
                        .where((l) => l.partyPending > 0 && !l.isPaymentOverdue)
                        .length),
                const SizedBox(width: 8),
                _filterChip('Settled', Colors.green,
                    widget.ledgers.where((l) => l.partyPending <= 0).length),
              ])),
        ),
        Expanded(
          child: filtered.isEmpty
              ? const Center(
                  child: Column(
                      mainAxisAlignment: MainAxisAlignment.center,
                      children: [
                      Icon(Icons.notifications_none,
                          size: 60, color: Colors.grey),
                      SizedBox(height: 12),
                      Text("No shared events yet",
                          style: TextStyle(
                              color: Colors.grey,
                              fontSize: 16,
                              fontWeight: FontWeight.w600)),
                      Text(
                          "Events appear here when loads are dispatched or LRs are posted",
                          style: TextStyle(color: Colors.grey, fontSize: 12),
                          textAlign: TextAlign.center),
                    ]))
              : ListView.separated(
                  padding: const EdgeInsets.all(16),
                  itemCount: filtered.length,
                  separatorBuilder: (_, __) => const SizedBox(height: 10),
                  itemBuilder: (_, i) {
                    final l = filtered[i];
                    final isRead = _readIds.contains(l.id);
                    final isRecent = i < 3 && !isRead;
                    final statusColor = l.isPaymentOverdue
                        ? Colors.red
                        : l.partyPending <= 0
                            ? Colors.green
                            : Colors.orange;
                    final statusLabel = l.partyPending <= 0
                        ? "Delivered & Settled"
                        : l.isPaymentOverdue
                            ? "Payment Overdue"
                            : "In Transit";
                    return GestureDetector(
                      onTap: () {
                        setState(() => _readIds.add(l.id));
                        Navigator.push(
                            context,
                            MaterialPageRoute(
                                builder: (_) => TripDetailScreen(
                                    ledger: l,
                                    userProfile: widget.userProfile,
                                    subscription: SubscriptionInfo(
                                        tier: SubscriptionTier.pro),
                                    drivers: const [],
                                    onUpdateLedger: (_) {},
                                    onKredXApply: (_) {})));
                      },
                      child: Container(
                        padding: const EdgeInsets.all(16),
                        decoration: BoxDecoration(
                            color: Colors.white,
                            borderRadius: BorderRadius.circular(16),
                            border: Border.all(
                                color: isRecent
                                    ? statusColor.withOpacity(0.4)
                                    : Colors.grey.shade200),
                            boxShadow: isRecent
                                ? [
                                    BoxShadow(
                                        color: statusColor.withOpacity(0.1),
                                        blurRadius: 10)
                                  ]
                                : []),
                        child: Row(
                            crossAxisAlignment: CrossAxisAlignment.start,
                            children: [
                              Container(
                                  padding: const EdgeInsets.all(10),
                                  decoration: BoxDecoration(
                                      color: statusColor.withOpacity(0.1),
                                      borderRadius: BorderRadius.circular(12)),
                                  child: Icon(
                                      l.partyPending <= 0
                                          ? Icons.check_circle_rounded
                                          : l.isPaymentOverdue
                                              ? Icons.warning_rounded
                                              : Icons.local_shipping_rounded,
                                      color: statusColor,
                                      size: 22)),
                              const SizedBox(width: 12),
                              Expanded(
                                  child: Column(
                                      crossAxisAlignment:
                                          CrossAxisAlignment.start,
                                      children: [
                                    Row(
                                        mainAxisAlignment:
                                            MainAxisAlignment.spaceBetween,
                                        children: [
                                          Expanded(
                                              child: Text(l.partyName,
                                                  style: const TextStyle(
                                                      fontWeight:
                                                          FontWeight.w800,
                                                      fontSize: 14,
                                                      color: Color(0xFF0F172A)),
                                                  overflow:
                                                      TextOverflow.ellipsis)),
                                          Container(
                                              padding:
                                                  const EdgeInsets.symmetric(
                                                      horizontal: 8,
                                                      vertical: 3),
                                              decoration: BoxDecoration(
                                                  color: statusColor
                                                      .withOpacity(0.1),
                                                  borderRadius:
                                                      BorderRadius.circular(8)),
                                              child: Text(statusLabel,
                                                  style: TextStyle(
                                                      color: statusColor,
                                                      fontSize: 9,
                                                      fontWeight:
                                                          FontWeight.w800))),
                                        ]),
                                    const SizedBox(height: 4),
                                    Text("${l.vehicleNo} • ${l.materialName}",
                                        style: const TextStyle(
                                            color: Color(0xFF64748B),
                                            fontSize: 12)),
                                    Text(l.route,
                                        style: const TextStyle(
                                            color: Color(0xFF94A3B8),
                                            fontSize: 11),
                                        maxLines: 1,
                                        overflow: TextOverflow.ellipsis),
                                    const SizedBox(height: 8),
                                    Row(children: [
                                      _infoTag(
                                          "Rs.${l.freightBilled.toStringAsFixed(0)}",
                                          const Color(0xFF0EA5E9)),
                                      const SizedBox(width: 6),
                                      if (l.driverName != null)
                                        _infoTag(l.driverName!, Colors.purple),
                                      const SizedBox(width: 6),
                                      _infoTag(l.date, Colors.grey),
                                    ]),
                                    if (l.partyPending > 0) ...[
                                      const SizedBox(height: 8),
                                      Row(children: [
                                        const Icon(Icons.picture_as_pdf,
                                            color: Color(0xFFF97316), size: 14),
                                        const SizedBox(width: 6),
                                        Text("Tap to view & download LR",
                                            style: const TextStyle(
                                                color: Color(0xFFF97316),
                                                fontSize: 11,
                                                fontWeight: FontWeight.w600)),
                                      ]),
                                    ],
                                  ])),
                            ]),
                      ),
                    );
                  }),
        ),
      ]),
    );
  }

  Widget _filterChip(String label, Color c, int count) => GestureDetector(
      onTap: () => setState(() => _filter = label),
      child: AnimatedContainer(
        duration: const Duration(milliseconds: 150),
        padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 5),
        decoration: BoxDecoration(
            color: _filter == label ? c.withOpacity(0.25) : c.withOpacity(0.08),
            borderRadius: BorderRadius.circular(20),
            border: Border.all(
                color: _filter == label ? c : c.withOpacity(0.3),
                width: _filter == label ? 1.5 : 1)),
        child: Row(mainAxisSize: MainAxisSize.min, children: [
          Text(label,
              style: TextStyle(
                  color: c,
                  fontSize: 11,
                  fontWeight:
                      _filter == label ? FontWeight.w900 : FontWeight.w600)),
          if (count > 0) ...[
            const SizedBox(width: 5),
            Container(
                padding: const EdgeInsets.symmetric(horizontal: 5, vertical: 1),
                decoration: BoxDecoration(
                    color: c.withOpacity(0.2),
                    borderRadius: BorderRadius.circular(8)),
                child: Text('$count',
                    style: TextStyle(
                        color: c, fontSize: 9, fontWeight: FontWeight.w800))),
          ],
        ]),
      ));

  Widget _infoTag(String label, Color c) => Container(
      padding: const EdgeInsets.symmetric(horizontal: 7, vertical: 3),
      decoration: BoxDecoration(
          color: c.withOpacity(0.08), borderRadius: BorderRadius.circular(6)),
      child: Text(label,
          style:
              TextStyle(color: c, fontSize: 10, fontWeight: FontWeight.w600)));
}

