                              color: PdfColor.fromHex('#059669')))),
                  pw.Padding(
                      padding: const pw.EdgeInsets.all(8),
                      child: pw.Text('Rs.${d.monthlySalary.toStringAsFixed(0)}',
                          style: pw.TextStyle(
                              fontSize: 10, fontWeight: pw.FontWeight.bold))),
                ]),
                ...d.transactions.take(8).map((tx) => pw.TableRow(children: [
                      pw.Padding(
                          padding: const pw.EdgeInsets.all(8),
                          child: pw.Text('${tx.note} (${tx.date})',
                              style: pw.TextStyle(fontSize: 9))),
                      pw.Padding(
                          padding: const pw.EdgeInsets.all(8),
                          child: pw.Text(tx.type.name,
                              style: pw.TextStyle(
                                  fontSize: 9,
                                  color: tx.amount >= 0
                                      ? PdfColor.fromHex('#059669')
                                      : PdfColor.fromHex('#DC2626')))),
                      pw.Padding(
                          padding: const pw.EdgeInsets.all(8),
                          child: pw.Text(
                              'Rs.${tx.amount.abs().toStringAsFixed(0)}',
                              style: pw.TextStyle(
                                  fontSize: 9,
                                  fontWeight: pw.FontWeight.bold,
                                  color: tx.amount >= 0
                                      ? PdfColor.fromHex('#059669')
                                      : PdfColor.fromHex('#DC2626')))),
                    ])),
              ],
            ),
            pw.SizedBox(height: 12),
            // Net payable
            pw.Container(
              padding: const pw.EdgeInsets.all(12),
              decoration: pw.BoxDecoration(
                color: d.balance >= 0
                    ? PdfColor.fromHex('#DCFCE7')
                    : PdfColor.fromHex('#FEE2E2'),
                borderRadius: const pw.BorderRadius.all(pw.Radius.circular(6)),
              ),
              child: pw.Row(
