                children: [
                  pw.Text('NET PAYABLE TO DRIVER',
                      style: pw.TextStyle(
                          fontWeight: pw.FontWeight.bold, fontSize: 12)),
                  pw.Text('Rs.${d.balance.abs().toStringAsFixed(0)}',
                      style: pw.TextStyle(
                          fontWeight: pw.FontWeight.bold,
                          fontSize: 16,
                          color: d.balance >= 0
                              ? PdfColor.fromHex('#059669')
                              : PdfColor.fromHex('#DC2626'))),
                ],
              ),
            ),
            pw.SizedBox(height: 20),
            pw.Row(children: [
              pw.Expanded(
                  child: pw.Column(
                      crossAxisAlignment: pw.CrossAxisAlignment.center,
                      children: [
                    pw.Container(height: 1, color: PdfColors.grey400),
                    pw.SizedBox(height: 4),
                    pw.Text('Driver Signature',
                        style: pw.TextStyle(
                            fontSize: 10, color: PdfColors.grey600)),
                  ])),
              pw.SizedBox(width: 40),
              pw.Expanded(
                  child: pw.Column(
                      crossAxisAlignment: pw.CrossAxisAlignment.center,
                      children: [
                    pw.Container(height: 1, color: PdfColors.grey400),
                    pw.SizedBox(height: 4),
                    pw.Text('Authorized Signatory',
                        style: pw.TextStyle(
                            fontSize: 10, color: PdfColors.grey600)),
                  ])),
            ]),
            pw.Spacer(),
            pw.Text(
                'Generated by Route Master ERP v5.0 | ${now.day}/${now.month}/${now.year}',
                style: pw.TextStyle(fontSize: 8, color: PdfColors.grey500)),
          ],
        ),
      ));
      await Printing.layoutPdf(
        onLayout: (_) async => pdf.save(),
        name: 'SalarySlip_${d.name.replaceAll(" ", "_")}_$monthStr.pdf',
      );
    } catch (e) {
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(SnackBar(
          backgroundColor: Colors.red,
          content: Text('PDF error: $e'),
        ));
      }
    }
  }

